import type { Drill } from "./types";

// Industrial / early drills, keyed by module slug — 25 per module.
// Machine operator / assembler / processing-line worker: shift handoffs, defect flags,
// machine-fault reports, near-miss reports, requests to the line supervisor. Merged into course.ts.
export const INDUSTRIAL_EARLY_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-mfg-early-01","level":"early","profession":"industrial","title":"The buried breakdown call","scenario":"Press 4 just stopped mid-cycle and won't restart. You key the radio to call your supervisor, but your instinct is to describe the weird sound it made, what you were running, and what you tried before saying the line is down.","task":"Write the 1-2 sentence radio call that leads with what's down and what you need.","tips":["First words: which machine is down and that production is stopped.","The ask comes right behind it: maintenance, and how fast.","The story of the noise can wait until someone is on the way."],"focus":["clarity","impact"],"placeholder":"Press 4 is down and the line is stopped — I need maintenance at station 2."},
    {"id":"lead-mfg-early-02","level":"early","profession":"industrial","title":"The handoff that buries the jam","scenario":"Your shift is ending. The labeler has jammed roughly every 30 minutes all afternoon, but your handoff note starts with a calm recap of the morning, the counts, and the cleaning you did. The one thing the next operator must watch is in the last line.","task":"Rewrite the opening of the handoff note so the labeler warning comes first.","tips":["Line one = the thing that will bite them if they miss it.","Everything that ran fine can come after.","Tell them what to do when it jams, not just that it does."],"focus":["structure","clarity"],"placeholder":"Watch the labeler — it's jammed about every 30 minutes all afternoon."},
    {"id":"lead-mfg-early-03","level":"early","profession":"industrial","title":"The out-of-spec caps","scenario":"Your hourly check shows cap torque reading over the spec limit on the last several bottles. Product is still flowing toward packing. Your message to QC starts with how the morning checks were all fine.","task":"Write a 1-2 sentence message to QC that leads with the out-of-spec result and the hold.","tips":["Lead with the verdict: out of spec, product needs a hold.","Say what's affected — line, product, since when.","The fine morning checks are background, not the headline."],"focus":["clarity","impact"],"placeholder":"Line 2 cap torque is reading over spec — holding product from the last hour."},
    {"id":"lead-mfg-early-04","level":"early","profession":"industrial","title":"The materials request with an hour left","scenario":"You're down to two rolls of shrink film — about an hour of running at current speed. You start typing a long message to your supervisor about how usage has been higher than normal today.","task":"Write a message that puts the ask — more film, and by when — in the first sentence.","tips":["Lead with what you need and the deadline: film within the hour.","One sentence on why is plenty.","A clear ask gets a forklift moving; a story doesn't."],"focus":["clarity","concision"],"placeholder":"I need two more pallets of shrink film at line 2 within the hour —"},
    {"id":"lead-mfg-early-05","level":"early","profession":"industrial","title":"The near-miss report opener","scenario":"You almost slipped on hydraulic oil pooling near the press walkway — caught yourself on the rail. You're filling out the near-miss form, and your draft opens with what you were carrying and where you were headed.","task":"Write the first sentence of the report so the hazard and the almost-injury lead.","tips":["First sentence: the hazard and what nearly happened.","Location matters — name the exact spot.","Your errand that day is context, not the point."],"focus":["clarity","precision"],"placeholder":"Oil pooling on the walkway beside press 4 nearly caused a slip —"},
    {"id":"lead-mfg-early-06","level":"early","profession":"industrial","title":"The relief request you keep softening","scenario":"You need a restroom break and can't leave the filler unattended. Your message to the line lead starts with 'sorry to bother you, I know everyone's busy, but whenever someone gets a chance...'","task":"Write a 1-sentence request that leads with what you need and for how long.","tips":["Lead with the ask: relief at the filler, five minutes.","Cut the apology warm-up — this is a normal request.","Say where you are so the relief goes to the right station."],"focus":["clarity","concision"]},
    {"id":"lead-mfg-early-07","level":"early","profession":"industrial","title":"The scrap spike message","scenario":"Rejects on your line jumped from the usual 4-5 an hour to over 40 this past hour, all short-fills. You start drafting a message that walks through your whole troubleshooting before naming the number.","task":"Write a 2-sentence message that leads with the spike and the defect type.","tips":["The number is the news: 40 rejects this hour versus a normal 5.","Name the defect in the same breath — short-fills.","What you've checked so far is sentence two, not sentence one."],"focus":["impact","precision"],"placeholder":"Rejects on line 3 jumped to 40 this hour, all short-fills —"},
    {"id":"lead-mfg-early-08","level":"early","profession":"industrial","title":"The question hiding in the work order","scenario":"The work order says to run today's lot at the 'revised fill weight,' but the spec sheet at your station still shows the old number. You start writing your supervisor a long explanation of both documents before asking which one to follow.","task":"Rewrite the message so the question comes first.","tips":["Ask in sentence one: which fill weight applies to this lot?","Give the two conflicting numbers as the only context needed.","A crisp question gets answered before the lot starts."],"focus":["clarity","concision"],"placeholder":"Quick check before I start lot 4471: is the fill weight 505 g or the 512 g on the station spec sheet?"},
    {"id":"lead-mfg-early-09","level":"early","profession":"industrial","title":"The yes/no you turn into a paragraph","scenario":"Your supervisor texts: 'Can you run through lunch if we get you relief for a late break?' The answer is yes. Your draft reply explains your morning, your break schedule, and your energy level before getting there.","task":"Write a reply that answers first, then adds the one condition that matters.","tips":["First word: yes or no.","One condition is fine — keep it to a clause.","Don't make them hunt for the answer they asked for."],"focus":["concision","clarity"]},
    {"id":"lead-mfg-early-10","level":"early","profession":"industrial","title":"The downtime entry that hides the cause","scenario":"The line was down 35 minutes this morning. Your logbook draft starts with the weather, the late material delivery backstory, and the mood on the floor before mentioning the conveyor belt tracking fault that actually stopped things.","task":"Write the first line of the downtime entry: what stopped, why, for how long.","tips":["One line carries it: fault, machine, minutes lost.","Whoever reads the log later needs the cause fast.","Backstory only if it changes what maintenance should do."],"focus":["precision","structure"],"placeholder":"Line down 35 min, 09:10-09:45 — conveyor belt tracking fault at the transfer."},
    {"id":"lead-mfg-early-11","level":"early","profession":"industrial","title":"The verbal handoff with one hot item","scenario":"The incoming operator is walking up and you have two minutes. Zone 2 of the oven has been running 10 degrees hot and you've been compensating manually — that's the one thing they can't miss. You tend to start handoffs with the full shift chronology.","task":"Write the first two sentences you'd say, leading with the oven issue and what to do about it.","tips":["Open with the live issue and the workaround.","Say it as an instruction they can act on, not a story.","The rest of the shift recap comes after — if there's time."],"focus":["clarity","impact"]},
    {"id":"lead-mfg-early-12","level":"early","profession":"industrial","title":"The work order that starts with a novel","scenario":"You're writing a maintenance work order for the case sealer. Your draft opens with three sentences about how long you've worked around the problem. The actual symptom — top flaps not sealing on the left side — shows up in line four.","task":"Rewrite the work order description so the symptom is the first line.","tips":["Lead with what the machine is doing wrong, specifically.","Maintenance triages by the first line — make it the fault.","How long it's been happening is useful, second."],"focus":["clarity","precision"],"placeholder":"Case sealer: top flaps not sealing on the left side — started mid-shift Tuesday."},
    {"id":"lead-mfg-early-13","level":"early","profession":"industrial","title":"The count that came up short","scenario":"End of shift and your count is 300 units short of the order. Your supervisor needs to know before they confirm the shipment. Your draft message opens with everything that went right today.","task":"Write a 2-sentence message that leads with the shortfall.","tips":["The number they need is the shortfall — put it first.","One sentence on the main reason, no more.","Bad news early beats bad news discovered at shipping."],"focus":["clarity","impact"],"placeholder":"We're 300 units short on order 8823 —"},
    {"id":"lead-mfg-early-14","level":"early","profession":"industrial","title":"The bypassed guard","scenario":"You've just noticed the interlock on the palletizer gate has been taped over so the door reads closed when it isn't. This needs to reach your supervisor now. Your draft starts with how you happened to be walking past.","task":"Write a message that leads with the hazard and that the machine shouldn't run.","tips":["First sentence: the safety device is defeated, machine needs to stop.","Name the machine and the device exactly.","How you found it is for the follow-up, not the alert."],"focus":["impact","clarity"],"placeholder":"The palletizer gate interlock is taped over — it needs to be locked out until it's fixed."},
    {"id":"lead-mfg-early-15","level":"early","profession":"industrial","title":"Keep running or stop?","scenario":"Parts coming off the molder have a faint flow line — borderline, maybe acceptable, maybe not. You need your supervisor's call before another hour of production stacks up. Your draft describes the molding process at length before asking.","task":"Write a message that puts the decision first: keep running or stop for a check?","tips":["Lead with the choice you need made and by when.","One sentence describing the defect is enough for the ask.","Bound it: every hour of waiting is another hour of maybe-scrap."],"focus":["clarity","impact"],"placeholder":"Need a call on line 5: keep running or stop? Parts show a faint flow line —"},
    {"id":"lead-mfg-early-16","level":"early","profession":"industrial","title":"The mislabeled pallet","scenario":"You just noticed a finished pallet carries labels for the 500 ml product, but it's stacked with 750 ml cases. It's staged in the shipping lane. Your message to the shipping lead starts with how the label printer has been acting up.","task":"Write a message that leads with 'hold that pallet' and which one it is.","tips":["First words: don't ship pallet X.","Identify it so they can find it fast — lane, label, product.","Printer troubles are the why, not the what."],"focus":["clarity","impact"],"placeholder":"Hold the pallet in shipping lane 3 — it's labeled 500 ml but stacked with 750 ml cases."},
    {"id":"lead-mfg-early-17","level":"early","profession":"industrial","title":"The absence you're burying","scenario":"You have a medical appointment tomorrow and will miss the first four hours of your shift. Your text to your supervisor opens with two sentences of apology and how you tried to reschedule.","task":"Write a 1-2 sentence message that states the absence and the hours up front.","tips":["Lead with the fact: out until 10:00 tomorrow.","One line of reason is plenty.","End with anything that helps them plan — your station, your tasks."],"focus":["concision","clarity"]},
    {"id":"lead-mfg-early-18","level":"early","profession":"industrial","title":"The forklift request that wanders","scenario":"You need the empty pallet stack removed and two pallets of cartons brought to line 6 before the 1:00 changeover. Your radio call to the material handler starts with a recap of this morning's deliveries.","task":"Write a 1-2 sentence radio call that leads with the two moves and the deadline.","tips":["Lead with the moves: what, where, by when.","Two asks — keep them in one breath, clearly separated.","The morning's history doesn't help them drive."],"focus":["clarity","concision"],"placeholder":"Line 6 needs two pallets of cartons and the empties pulled before the 1:00 changeover."},
    {"id":"lead-mfg-early-19","level":"early","profession":"industrial","title":"The worn tool warning","scenario":"The trim die is leaving a rougher edge each shift — parts still pass, but the trend is clear. You want your supervisor to schedule a die change before parts start failing. Your draft opens with a history of the die's whole life.","task":"Write a 2-sentence heads-up that leads with the risk and the ask.","tips":["Lead with where this is heading: edges will be out of spec soon.","The ask is a scheduled die change — say it plainly.","One data point of the trend is enough support."],"focus":["impact","precision"],"placeholder":"The trim die on line 1 is wearing — edges are getting rougher each shift and we'll start failing parts soon."},
    {"id":"lead-mfg-early-20","level":"early","profession":"industrial","title":"Your fifteen seconds at the huddle","scenario":"At the morning huddle each operator gives a line status. Yesterday you ran to plan except for one 20-minute jam that's now fixed. You tend to narrate the whole day shift-hour by shift-hour.","task":"Write the 1-2 sentence status you'd say, headline first.","tips":["Lead with the verdict: ran to plan.","The one exception gets one clause, including that it's resolved.","Fifteen seconds — everything else is a follow-up conversation."],"focus":["concision","structure"]},
    {"id":"lead-mfg-early-21","level":"early","profession":"industrial","title":"The lot-number mistake","scenario":"You realize you wrote the wrong lot number on the last two hours of batch records — a transposed digit. It's fixable, but QC needs to know before those records move on. Your draft message spends four sentences explaining how the mix-up happened.","task":"Write a message that leads with the error and what needs correcting.","tips":["First sentence: what's wrong on which records.","Owning it plainly reads better than explaining it away.","End with the fix you're proposing, not more backstory."],"focus":["clarity","impact"],"placeholder":"I wrote lot 4417 instead of 4471 on the batch records from 12:00-14:00 —"},
    {"id":"lead-mfg-early-22","level":"early","profession":"industrial","title":"The expired calibration sticker","scenario":"The check-weigher you've been using all morning has a calibration sticker that expired last week. That may put your morning's weight checks in question. Your draft to QC opens with how you only just noticed.","task":"Write a 2-sentence message that leads with the finding and its consequence.","tips":["Lead with the fact: scale out of calibration since last week.","Consequence in the same breath: this morning's checks are in question.","When you noticed matters less than what it affects."],"focus":["clarity","precision"],"placeholder":"The check-weigher on line 2 is past its calibration date — this morning's weight checks may not be valid."},
    {"id":"lead-mfg-early-23","level":"early","profession":"industrial","title":"The suggestion you keep introducing","scenario":"You've figured out that pre-staging the next order's labels during each run would cut changeover time. You want to tell your supervisor, but your draft has three sentences of 'I know I'm still new here, but I was thinking...'","task":"Write the suggestion so the idea itself is sentence one.","tips":["Lead with the proposal in plain words.","The benefit rides in the same sentence or the next: faster changeovers.","Cut the credentials disclaimer — the idea stands on its own."],"focus":["clarity","impact"],"placeholder":"Suggestion: pre-stage the next order's labels during each run —"},
    {"id":"lead-mfg-early-24","level":"early","profession":"industrial","title":"The training request that circles","scenario":"You want to get trained on the palletizer so you can cover when the regular operator is out — it would help the whole line. Your draft message to your supervisor wanders through your career thoughts before landing on the ask.","task":"Write a 2-sentence request that leads with the ask and the benefit to the line.","tips":["Sentence one: the ask — palletizer training.","Sentence two: why it helps the line, not just you.","Make it easy to say yes: suggest when it could happen."],"focus":["clarity","structure"]},
    {"id":"lead-mfg-early-25","level":"early","profession":"industrial","title":"The grinding gearbox text","scenario":"There's a new grinding noise from the conveyor gearbox — the line still runs, but it sounds like it's getting worse. You're texting your supervisor and your thumb has typed three sentences of hedging so far.","task":"Write a 1-2 sentence text that leads with the problem and your read on the urgency.","tips":["Lead with the symptom and the machine.","Give your read: still running, but worsening — worth a look today.","Short beats thorough in a text; detail can follow by radio."],"focus":["clarity","impact"],"placeholder":"Conveyor gearbox on line 4 has a new grinding noise — still running but getting worse."}
  ],
  "start-with-the-audience": [
    {"id":"audience-mfg-early-01","level":"early","profession":"industrial","title":"What maintenance actually needs","scenario":"The filler keeps faulting out and you're frustrated. Your draft work-order note reads: 'This machine is junk, it's been fighting me all day, somebody needs to actually fix it this time.' The mechanic reading it needs symptoms, timing, and what changed — not your mood.","task":"Rewrite the note in 2-3 sentences with what a mechanic needs to start diagnosing.","tips":["Give the fault message or behavior, exactly as the machine shows it.","Say when it started and how often it happens.","Mention anything that changed: new material, new setting, recent work."],"focus":["audience","precision"],"placeholder":"Filler faults with 'E-42 no bottle' about every 10 minutes, started after the 10:00 material change."},
    {"id":"audience-mfg-early-02","level":"early","profession":"industrial","title":"Same downtime, told to the supervisor","scenario":"The same filler fault has cost you 50 minutes of production. Now you're updating your supervisor. They don't need the fault code — they need the production impact and when the line will run normally again.","task":"Write a 2-3 sentence update framed around output and recovery time.","tips":["Lead with what it means for the shift's numbers.","Give a recovery estimate, even a rough one.","Save the mechanical detail for maintenance — the supervisor plans people and orders."],"focus":["audience","clarity"],"placeholder":"The filler faults have cost us about 50 minutes — we'll finish the order roughly 400 units short unless..."},
    {"id":"audience-mfg-early-03","level":"early","profession":"industrial","title":"The defect message QC can act on","scenario":"You're flagging seal failures to the QC lab. Your instinct is to describe your machine settings in detail. The lab needs different things: which lot, what time window, how many samples failed out of how many checked.","task":"Write a 2-3 sentence message with the lot, window, and sample numbers QC needs.","tips":["QC thinks in lots and time windows — give both.","Failures out of samples checked, not just 'a few bad ones'.","Your machine settings only matter if the lab asks."],"focus":["audience","precision"],"placeholder":"Lot 5512, 13:00-14:00 window: 3 of 10 seal checks failed on the front edge."},
    {"id":"audience-mfg-early-04","level":"early","profession":"industrial","title":"Covering instructions for your relief","scenario":"A floater is covering your station for your 30-minute lunch. You know the machine's quirks by feel — the sensor you tap, the reject gate that sticks. Your draft note says 'you know the drill, just keep it running.' They don't know the drill.","task":"Write a 3-4 sentence note that lets someone unfamiliar run the station safely for 30 minutes.","tips":["Assume they know nothing about this machine's quirks.","Give the two or three things that actually come up in a half hour.","Tell them when to stop and call rather than improvise."],"focus":["audience","clarity"]},
    {"id":"audience-mfg-early-05","level":"early","profession":"industrial","title":"The weekend crew doesn't know your line","scenario":"A weekend crew that rarely runs your line will finish your order. You're leaving a note. Your draft is full of shorthand: 'usual settings,' 'the sticky spot,' 'run it like we did for the June order.' None of that means anything to them.","task":"Rewrite the note in 3-4 sentences with the shorthand spelled out.","tips":["Every 'usual' and 'like last time' needs a number or a location.","Name the settings, don't reference memories they don't have.","Point to where the spec sheet lives in case they need more."],"focus":["audience","precision"],"placeholder":"Run at 60/min with heat at 340 — the setpoint on the spec sheet, not what's dialed in."},
    {"id":"audience-mfg-early-06","level":"early","profession":"industrial","title":"Talking to the visiting engineer","scenario":"A plant engineer is investigating why your line's reject rate doubled. You're tempted to offer your theory in half-remembered technical terms. What they actually need is what you observe: when it happens, what the rejects look like, what you've seen change.","task":"Write 3-4 sentences telling the engineer what you observe, without guessing at causes in their language.","tips":["Report what you see and when — you're the eyes on the line.","Plain words beat borrowed jargon used wrong.","It's fine to add a hunch — labeled as a hunch, at the end."],"focus":["audience","precision"]},
    {"id":"audience-mfg-early-07","level":"early","profession":"industrial","title":"Training words for a first-day hire","scenario":"You're showing a new hire the case packer. You catch yourself saying 'if it faults, just do the usual reset, and watch the thing by the gate.' On day one, 'the usual reset' and 'the thing' are noise.","task":"Rewrite that instruction in 2-3 sentences a first-day hire can follow alone.","tips":["Name the buttons, parts, and locations — no 'the thing'.","One action per sentence, in the order they'd do it.","Tell them what 'working again' looks like so they know they succeeded."],"focus":["audience","clarity"],"placeholder":"If the case packer stops and the red light comes on, press the blue RESET on the right side panel, then..."},
    {"id":"audience-mfg-early-08","level":"early","profession":"industrial","title":"A note the sanitation crew can use","scenario":"Sanitation cleans your area tonight. The new proximity sensor bracket on the infeed can't get sprayed directly, and the calibration weights on the shelf can't be moved. Your draft note explains why in operator terms they don't need.","task":"Write a 2-sentence note that tells sanitation exactly what to avoid and where it is.","tips":["They need the what and where, not the engineering why.","Describe locations the way someone new to the line would find them.","Two clear don'ts beat a paragraph of context."],"focus":["audience","concision"]},
    {"id":"audience-mfg-early-09","level":"early","profession":"industrial","title":"Plain terms for the planner","scenario":"The production planner messages: 'Will order 7734 finish today?' Your draft answer is machine-speak: 'Depends if the E-stop gremlin on the infeed behaves and the film splice holds.' The planner schedules trucks — they need a yes, no, or a time.","task":"Write a 2-sentence reply in the planner's terms: a time and a confidence level.","tips":["Answer in their currency: done by when, how sure.","Translate the machine risk into schedule risk, plainly.","Offer the trigger: 'I'll flag you by 2:00 if it slips.'"],"focus":["audience","clarity"],"placeholder":"Yes — on pace to finish by 4:30. One machine issue could push it an hour; I'll flag you by 2:00 if so."},
    {"id":"audience-mfg-early-10","level":"early","profession":"industrial","title":"The delay, told to shipping","scenario":"A changeover ran long and the last three pallets of an order will be ready two hours later than planned. The shipping lead is loading the truck now. Your draft explains the changeover problems in detail they can't use.","task":"Write a 2-sentence message with what shipping needs: which pallets, ready when.","tips":["Shipping thinks in pallets and dock times — answer in those.","The changeover story doesn't load trucks; cut it.","Say what IS ready now so they can keep working."],"focus":["audience","concision"],"placeholder":"Last 3 pallets of order 7734 will be ready at 3:30, not 1:30. The first 9 are staged and ready now."},
    {"id":"audience-mfg-early-11","level":"early","profession":"industrial","title":"What the safety coordinator needs","scenario":"You're reporting a near-miss to the safety coordinator: a forklift backed toward you at the blind corner by line 5. Your draft focuses on how startled you were. The coordinator's job is prevention — they need the conditions that made it possible.","task":"Write 3-4 sentences giving the coordinator the conditions and a prevention angle.","tips":["Describe the setup: blind corner, no mirror, noise covering the alarm.","What made it possible matters more than how it felt.","Suggest what would have prevented it — you know the corner best."],"focus":["audience","impact"]},
    {"id":"audience-mfg-early-12","level":"early","profession":"industrial","title":"The downtime code someone reads upstairs","scenario":"You're entering last hour's downtime into the tracking system. Someone in the office will roll your entry into a report without ever seeing the line. Your draft note reads 'same as always, sensor thing.' Upstairs, that's useless.","task":"Write a 1-2 sentence downtime note that stands alone for a reader who's never seen your line.","tips":["Write for a stranger: machine, fault, duration.","'Same as always' hides a pattern the report should show — name it.","If it recurs, say so with a count: fourth time this week."],"focus":["audience","precision"],"placeholder":"Infeed photo-eye lost signal, line down 22 min — fourth occurrence this week on line 3."},
    {"id":"audience-mfg-early-13","level":"early","profession":"industrial","title":"The spec sheet, translated for a temp","scenario":"A temp is doing visual checks on your line today. The spec sheet says 'reject units exhibiting seal delamination exceeding 3 mm from the leading edge.' They've been on the floor two hours and won't parse that.","task":"Rewrite the instruction in 1-2 sentences a temp can apply in one glance per part.","tips":["Turn the spec into what the eye should look for.","Give a physical comparison for 3 mm they can hold in mind.","Tell them what to do with a bad one — where it goes."],"focus":["audience","clarity"],"placeholder":"If the seal edge is peeling back more than the width of two stacked quarters, put it in the red bin."},
    {"id":"audience-mfg-early-14","level":"early","profession":"industrial","title":"The reference nobody else has","scenario":"You're writing a handoff to an operator who was off all week: 'Run it the way we set it up Tuesday, after the thing with the mixer.' They weren't here Tuesday. There was no 'thing' in their week.","task":"Rewrite the handoff line in 2-3 sentences with the missing context filled in.","tips":["Beat the curse of knowledge: they don't share your week.","Replace the memory reference with the actual settings or steps.","One sentence of what happened, then the instruction that follows from it."],"focus":["audience","clarity"]},
    {"id":"audience-mfg-early-15","level":"early","profession":"industrial","title":"The tool crib request","scenario":"You need a replacement part from the tool crib. Your draft: 'I need the roller thingy for the conveyor, the one that keeps going bad.' The attendant serves forty machines — they need a part name, size, or machine number to find it.","task":"Write a 1-2 sentence request the crib attendant can fill without follow-up questions.","tips":["Machine number and part name get you the right part first try.","If you don't know the name, describe location and function precisely.","Say if it's urgent — the crib triages too."],"focus":["audience","precision"],"placeholder":"Line 4 outfeed conveyor: I need the return roller for the tail end — the 18-inch one. Line's still running but it's squealing."},
    {"id":"audience-mfg-early-16","level":"early","profession":"industrial","title":"One message, one audience","scenario":"You've drafted one long message about a bearing failure that tries to serve everyone: fault details for maintenance, output impact for your supervisor, and a hold request for QC. It serves no one — each reader wades through two-thirds that isn't for them.","task":"Pick the supervisor as the audience and rewrite the message in 2-3 sentences for them alone.","tips":["One primary reader per message — the others get their own.","The supervisor's questions: how much output lost, what do you need, when back up?","It's fine to say 'maintenance and QC have the details' in one clause."],"focus":["audience","structure"]},
    {"id":"audience-mfg-early-17","level":"early","profession":"industrial","title":"The right altitude for 'how's the line?'","scenario":"Your supervisor walks past and asks 'how's line 2?' You've been deep in a sensor alignment for an hour, and your instinct is to describe the alignment in detail. That's the wrong altitude — they asked about the line.","task":"Write the 1-2 sentence answer at the altitude the question was asked.","tips":["Answer at line level: running or not, on pace or behind.","The sensor work is a supporting clause at most.","If they want the detail, they'll ask — leave the door open."],"focus":["audience","concision"],"placeholder":"Running and on pace — I've been tuning a sensor that was causing false rejects, sorted now."},
    {"id":"audience-mfg-early-18","level":"early","profession":"industrial","title":"PPE words for a visitor","scenario":"A contractor is about to walk your area without earplugs or safety glasses. You need to stop them politely but without room for debate. Your draft over-explains plant policy history.","task":"Write the 1-2 sentences you'd say: the requirement, and where to get the gear.","tips":["State the rule as a fact of the area, not a personal preference.","Tell them where the dispenser is — make compliance easy.","Friendly and firm can be the same sentence."],"focus":["audience","clarity"]},
    {"id":"audience-mfg-early-19","level":"early","profession":"industrial","title":"Handoff to a floater from another line","scenario":"An operator from the bottling line is covering your packaging station tomorrow. They're experienced — just not here. Your draft handoff either over-explains basics they know or skips quirks they can't know. The trick is sorting which is which.","task":"Write a 3-4 sentence handoff that skips general knowledge and covers only this station's quirks.","tips":["They know machines; they don't know THIS machine.","Lead with the quirks that would surprise an experienced operator.","Skip anything true of every line in the plant."],"focus":["audience","structure"]},
    {"id":"audience-mfg-early-20","level":"early","profession":"industrial","title":"Why the pallet is on hold","scenario":"You've tagged a pallet ON HOLD, but material handlers move product all day and a tag alone sometimes isn't enough. You're adding a note. Your draft explains the quality theory behind the hold — the handler just needs to know not to move it, and until when.","task":"Write a 2-sentence note for the handler: don't move it, why in five words, who releases it.","tips":["The handler's question is 'can I move this?' — answer that.","Five words of why builds respect for the tag.","Name who can release it so they don't guess."],"focus":["audience","concision"],"placeholder":"Do not ship or move — failed seal check, waiting on QC. Only QC (ext. 4412) releases this pallet."},
    {"id":"audience-mfg-early-21","level":"early","profession":"industrial","title":"Describing the fault to the electrician","scenario":"The wrapper trips its breaker two or three times a shift. An electrician is coming. What they'll want: what's running when it trips, any pattern in timing, whether it trips on startup or mid-cycle. Your draft just says 'it keeps tripping, please fix.'","task":"Write 2-3 sentences with the pattern details an electrician would ask for anyway.","tips":["Trips at startup vs mid-cycle is diagnostic gold — say which.","Note what else is running when it happens.","Count and times, not 'keeps happening'."],"focus":["audience","precision"],"placeholder":"The wrapper trips its breaker mid-cycle, not at startup — twice yesterday (10:40, 14:15), once today, always while the heat tunnel is also on."},
    {"id":"audience-mfg-early-22","level":"early","profession":"industrial","title":"Supervisor or mechanic — pick the frame","scenario":"The stacker is slowly losing speed and you'll tell both your supervisor and the mechanic. To the mechanic it's a symptom story; to the supervisor it's a production risk. You're writing the supervisor version first and mechanical detail keeps creeping in.","task":"Write the 2-sentence supervisor version, framed entirely as production risk and ask.","tips":["Supervisor frame: what it threatens and what you need decided.","One clause of symptom is plenty — 'losing speed since Monday'.","The mechanic gets the full symptom story separately."],"focus":["audience","clarity"]},
    {"id":"audience-mfg-early-23","level":"early","profession":"industrial","title":"The procedure change at huddle","scenario":"Starting today, every torque check gets logged in the new binder, not the old sheet. You're telling your line crew at huddle. Your draft explains the audit history behind the change. The crew needs what changes for their hands, today.","task":"Write the 2-3 sentences you'd say: what changes, from when, what stays the same.","tips":["Lead with the action change: new binder, starting now.","One sentence of why keeps grumbling down — keep it short.","Say what hasn't changed so no one over-corrects."],"focus":["audience","clarity"]},
    {"id":"audience-mfg-early-24","level":"early","profession":"industrial","title":"A defect tag a stranger can act on","scenario":"You're tagging a bin of parts with undersized holes. Whoever picks up this bin — today, or in three weeks — will know nothing but what the tag says. Your draft says 'bad holes, do not use.'","task":"Write the 2-3 line tag: defect, scope, and what happens next.","tips":["Write for a reader with zero context, three weeks from now.","Defect, quantity, lot, date, your name — the tag's whole job.","Say the disposition if known: rework, scrap, or awaiting QC."],"focus":["audience","precision"],"placeholder":"HOLD - hole diameter under spec (all 4 holes). Approx 240 pcs, lot 3319, found 07/02, J. Reyes. Awaiting QC disposition."},
    {"id":"audience-mfg-early-25","level":"early","profession":"industrial","title":"The covering supervisor from another department","scenario":"Your supervisor is out; a supervisor from the warehouse is covering. They ask for your end-of-shift rundown. Your usual rundown leans on line shorthand — 'the usual reject gremlin,' 'ran Aunt Bessie' (the old backup labeler). They'll be lost.","task":"Write a 3-4 sentence rundown with zero line shorthand.","tips":["Nicknames and 'the usual' mean nothing outside your line.","Numbers travel across departments: units, minutes down, rejects.","Flag what needs a decision tonight vs what waits for your supervisor's return."],"focus":["audience","clarity"]}
  ],
  "structure-that-carries": [
    {"id":"structure-mfg-early-01","level":"early","profession":"industrial","title":"The handoff sorted into three buckets","scenario":"Your end-of-shift notes are a scattered list: cleaned filters, labeler jammed twice, order 8823 done, low on glue, oven zone 2 hot, counted spares. The incoming operator needs it sorted, not raw.","task":"Rewrite the handoff grouped under three headers: Running fine / Watch / Needs action.","tips":["Three buckets carry everything: fine, watch, act.","Put the buckets in order of urgency — action items first.","One line per item inside each bucket."],"focus":["structure","clarity"],"placeholder":"NEEDS ACTION: glue down to half a drum — order more before 6:00. WATCH: oven zone 2..."},
    {"id":"structure-mfg-early-02","level":"early","profession":"industrial","title":"SCQA for the film-staging idea","scenario":"You want to propose staging film rolls at the line during each run instead of fetching them at changeover. You have the idea but it comes out as a jumble. SCQA gives it bones: Situation, Complication, Question, Answer.","task":"Write the proposal in 4 sentences, one each for situation, complication, question, answer.","tips":["Situation: how changeovers work now, in one neutral sentence.","Complication: the 15 minutes lost fetching film each time.","Answer: your proposal, concrete enough to try Monday."],"focus":["structure","impact"]},
    {"id":"structure-mfg-early-03","level":"early","profession":"industrial","title":"PREP for the changeover question","scenario":"Your supervisor asks, on the spot: 'Should we run out this order before the changeover or cut it now?' You have a view. PREP keeps a spoken answer from wandering: Point, Reason, Example, Point again.","task":"Write your spoken answer in 4 sentences using PREP.","tips":["Point first: run it out, or cut now — commit.","One reason, one concrete example from today's run.","Restate the point in different words to land it."],"focus":["structure","clarity"],"placeholder":"Run the order out — it's 40 minutes and the changeover crew isn't free until 2:00 anyway."},
    {"id":"structure-mfg-early-04","level":"early","profession":"industrial","title":"The near-miss in three parts","scenario":"You're writing up the near-miss where a lift chain swung a load toward your station. Your draft mixes what happened, why, and what should change in one tangle. The report needs three clean sections.","task":"Write the report in 3 short parts: what happened, why it was possible, what would prevent it.","tips":["Part one is pure sequence — no blame, no fixes yet.","Part two names conditions: the load path over a walkway, no barrier.","Part three is one concrete prevention, not a wish list."],"focus":["structure","precision"]},
    {"id":"structure-mfg-early-05","level":"early","profession":"industrial","title":"The maintenance request in order","scenario":"You're reporting the vibrating feeder that's been surging. Your draft opens with your theory, doubles back to symptoms, then mentions when it started. Maintenance requests have a natural order: symptom, when it started, what you've tried.","task":"Write the request in 3 sentences following that order.","tips":["Symptom first, in the machine's own terms.","When it started — and what changed around then, if anything.","What you tried and what happened, so they don't repeat it."],"focus":["structure","precision"],"placeholder":"The parts feeder on line 6 surges — floods the track, then starves it. Started Tuesday after the hopper refill."},
    {"id":"structure-mfg-early-06","level":"early","profession":"industrial","title":"A logbook entry with a spine","scenario":"Your logbook entries come out stream-of-consciousness and nobody can find anything in them later. A good entry has a fixed spine: time, event, action taken, current status.","task":"Write one logbook entry for today's 20-minute conveyor stoppage using that four-part spine.","tips":["Same order every entry — readers learn where to look.","Event and action are different sentences; don't blend them.","Status is the last word: resolved, watching, or open."],"focus":["structure","precision"],"placeholder":"14:20 — conveyor stopped, drive belt slipped off the tail pulley. Re-tracked belt and tensioned. Resolved; watching for recurrence."},
    {"id":"structure-mfg-early-07","level":"early","profession":"industrial","title":"Three causes, not eleven complaints","scenario":"Today's downtime came from eleven separate stops, but when you list them they cluster: label feed issues, one long jam at the diverter, and short waits for material. Your supervisor needs the clusters, not the eleven.","task":"Write a 3-4 sentence downtime summary grouped into the three causes, biggest first.","tips":["Group first, then report — the reader shouldn't do the sorting.","Biggest time-loser leads.","Give minutes per group so the sizes are visible."],"focus":["structure","precision"]},
    {"id":"structure-mfg-early-08","level":"early","profession":"industrial","title":"One governing headline for the shift","scenario":"You're writing the shift summary. Underneath the details, the real story is simple: a good shift that beat target despite one supplier hiccup. Every detail should hang off that one idea — but your draft is a flat list.","task":"Write the summary: one governing headline sentence, then 3 supporting bullets.","tips":["The headline is the takeaway, not a topic — 'beat target despite X'.","Every bullet should support or qualify the headline.","A detail that fits no bucket probably doesn't belong."],"focus":["structure","clarity"],"placeholder":"Beat target by 300 units despite a late film delivery. - Output: 5,300 vs 5,000 plan..."},
    {"id":"structure-mfg-early-09","level":"early","profession":"industrial","title":"Defect, scope, containment","scenario":"You found cracked housings coming off the press. Your report needs three things in order: the defect, how far it spread (scope), and what's stopping more (containment). Your draft opens with containment and never sizes the scope.","task":"Write a 3-sentence report: defect, scope, containment — in that order.","tips":["Defect: what's wrong, precisely.","Scope: since when, how many, which lots — the reader's first fear.","Containment: what's stopping the bleed right now."],"focus":["structure","precision"],"placeholder":"Housings off press 2 are cracking at the corner boss. Affects roughly 2 hours of production, lot 6641 —"},
    {"id":"structure-mfg-early-10","level":"early","profession":"industrial","title":"The toolbox-talk comment that lands","scenario":"At the weekly toolbox talk you want to raise that stacked empty pallets keep blocking the fire-exit path. You have one minute. Unstructured, it becomes a ramble about pallets in general.","task":"Write your 3-sentence comment: the issue, why it matters, the one ask.","tips":["Name the specific issue and location up front.","One sentence of stakes — it's a fire path.","End on a single ask people can act on today."],"focus":["structure","impact"]},
    {"id":"structure-mfg-early-11","level":"early","profession":"industrial","title":"Ten gripes, three themes","scenario":"Your supervisor asked what's slowing the line down. You have ten scattered answers: missing tools, waiting on QC, label misprints, cluttered aisles, slow changeovers... They cluster into three themes if you sort them.","task":"Group the issues into 3 named themes and write one summary sentence per theme.","tips":["Find the natural buckets: waiting, workspace, equipment — whatever fits.","Name each theme in two or three words.","Sorted input gets acted on; a gripe list gets filed."],"focus":["structure","clarity"]},
    {"id":"structure-mfg-early-12","level":"early","profession":"industrial","title":"Two asks that keep tangling","scenario":"You need two things from your supervisor: a materials order approved today, and maintenance scheduled for the slow stacker this week. Your draft braids them together and both get lost.","task":"Write the message with the two asks cleanly separated — number them.","tips":["One ask per numbered line, each with its own deadline.","Don't let the reasons cross-contaminate — keep each ask's why with it.","Numbered asks get numbered answers."],"focus":["structure","clarity"],"placeholder":"Two things I need: 1) Glue order approved today — we run out Thursday. 2) ..."},
    {"id":"structure-mfg-early-13","level":"early","profession":"industrial","title":"Done, remaining, blocked","scenario":"Mid-changeover, your supervisor radios for status. The honest picture: guards are swapped and the dies are set, the feed rails still need adjusting, and you're stuck waiting on QC's first-piece check. Say it in that shape.","task":"Write a 3-sentence spoken status: done, remaining, blocked — in that order.","tips":["Fixed order means they can absorb it in one pass.","Blocked is the part they can help with — don't bury it last-second, but land on it.","Attach a time to 'remaining' if you can."],"focus":["structure","concision"],"placeholder":"Guards and dies are done. Feed rails need another 20 minutes. I'm blocked on QC's first-piece check — can you chase that?"},
    {"id":"structure-mfg-early-14","level":"early","profession":"industrial","title":"The training request, structured","scenario":"You want cross-training on the CNC saw. Your draft is one long sentence mixing what you want, why it helps, and when it could happen. Three short parts would carry it better.","task":"Write the request in 3 sentences: the what, the why-for-the-line, the when.","tips":["What: the specific skill and machine.","Why: frame it as coverage and flexibility for the line.","When: propose a low-cost slot, like slow Friday afternoons."],"focus":["structure","clarity"]},
    {"id":"structure-mfg-early-15","level":"early","profession":"industrial","title":"'Walk me through what happened'","scenario":"After the wrap-station jam damaged a guard, your supervisor says: 'Walk me through what happened.' A good walkthrough is chronological and flags the one decision point — not a defense, not a shrug.","task":"Write your 4-5 sentence spoken walkthrough in strict time order, flagging where you made a judgment call.","tips":["Time order, no skipping around — first this, then this.","Mark your decision point honestly: 'at that point I chose to...'.","End at the current state, not at an apology."],"focus":["structure","clarity"]},
    {"id":"structure-mfg-early-16","level":"early","profession":"industrial","title":"The deviation note on the batch record","scenario":"You had to restart the mixer mid-batch — a deviation that needs a note on the batch record. The note has a required shape: what deviated, why, what you did, who you told. Your draft is one run-on sentence.","task":"Write the deviation note in 3-4 short sentences covering all four parts.","tips":["One part per sentence — auditors read these years later.","Why should be observed fact, not speculation.","Name who you notified and when; that's half the note's job."],"focus":["structure","precision"],"placeholder":"Mixer stopped at 12 min into the 20-min cycle due to overload fault. Restarted and completed remaining 8 min per SOP-114. Notified..."},
    {"id":"structure-mfg-early-17","level":"early","profession":"industrial","title":"The 5S observation, grouped","scenario":"You did the weekly housekeeping walk and noted nine issues across the area. Raw, it's a wall of text. Grouped by zone — your station, the aisle, the staging area — it becomes actionable.","task":"Write the observations grouped under 3 zone headers, one line each per issue.","tips":["Group by where someone would stand to fix them.","Worst zone first.","Each line: the issue plus the fix, not just the complaint."],"focus":["structure","concision"]},
    {"id":"structure-mfg-early-18","level":"early","profession":"industrial","title":"PREP at the morning huddle","scenario":"At huddle, the lead asks each operator: 'Anything that'll stop us hitting plan today?' You know the answer is the low glue stock. Use PREP so your ten seconds carries: Point, Reason, Example, Point.","task":"Write your 3-4 sentence spoken huddle answer using PREP.","tips":["Point: yes — glue could stop us by mid-shift.","Reason and example: current stock vs usage rate.","Close by repeating the ask: order approved this morning."],"focus":["structure","concision"],"placeholder":"One thing: glue. We're at half a drum and we burn a drum a shift —"},
    {"id":"structure-mfg-early-19","level":"early","profession":"industrial","title":"Problem, proposal, benefit","scenario":"Your improvement idea — a second parts bin at station 3 so nobody walks mid-cycle — keeps coming out as a story about your afternoon. The suggestion form has room for about four sentences. Structure them: problem, proposal, benefit.","task":"Write the suggestion in 3-4 sentences: problem, proposal, benefit — with a number in the benefit.","tips":["Problem in observable terms: operators leave station 3 twice a cycle.","Proposal concrete enough to cost out: one bin, mounted where.","Benefit with a number: minutes saved per shift."],"focus":["structure","impact"]},
    {"id":"structure-mfg-early-20","level":"early","profession":"industrial","title":"One story-line for the ghost fault","scenario":"The sealer fault appears and vanishes, and your report keeps switching between telling it by time ('Monday it did X, Tuesday Y') and by symptom ('when it's hot it does X'). Pick one organizing idea — the pattern you believe — and hang everything on it.","task":"Write a 4-sentence report organized around one governing observation about the pattern.","tips":["Lead with the pattern you'd bet on: 'It tracks with temperature.'","Then arrange the evidence to test that one idea.","Note what doesn't fit — one honest sentence."],"focus":["structure","precision"],"placeholder":"The sealer fault tracks with heat: it appears after 2+ hours of running and vanishes after any long stop."},
    {"id":"structure-mfg-early-21","level":"early","profession":"industrial","title":"The hold message, in order","scenario":"You're messaging QC about a hold with photos attached. Your draft references 'the first photo' before explaining anything. Order the message so it reads clean: what's held, why, then what each photo shows.","task":"Write the message in that order — hold, reason, then a one-line caption per photo.","tips":["Words first, photos as evidence — not the reverse.","Caption each photo so it can't be misread.","End with what you need from QC and by when."],"focus":["structure","clarity"]},
    {"id":"structure-mfg-early-22","level":"early","profession":"industrial","title":"The shift-swap request","scenario":"You want to swap Friday's shift with a coworker who's already agreed. The request to your supervisor needs three things in order: the ask, the coverage plan, the confirmation that the coworker agreed. Your draft leads with your reasons for needing Friday off.","task":"Write the request in 3 sentences: ask, coverage, agreement.","tips":["The supervisor's first question is 'who covers?' — answer it second, right after the ask.","Your Friday plans need one clause at most.","Make approval one word: 'OK to proceed?'"],"focus":["structure","concision"],"placeholder":"Requesting to swap my Friday day shift with Sam's Saturday. Sam has agreed and is qualified on my station."},
    {"id":"structure-mfg-early-23","level":"early","profession":"industrial","title":"The week in three buckets","scenario":"Your supervisor asked for a short written summary of your week for the first time. You have scraps: numbers, two machine issues, a training session, a near-miss you reported. Sort before you write.","task":"Write the summary: one headline sentence, then 3 grouped bullets (output, issues, other).","tips":["Headline the week in one sentence before any detail.","Consistent buckets week over week make you easy to read.","Keep 'other' honest — two items max, or it's a junk drawer."],"focus":["structure","concision"]},
    {"id":"structure-mfg-early-24","level":"early","profession":"industrial","title":"Now versus when-you-can","scenario":"Your handoff mixes urgent items (reset the jam counter before startup, QC needs the retain samples by 7:00) with anytime items (spare belts came in, wipe the sensor lens when convenient). Undifferentiated, the urgent ones get missed.","task":"Rewrite the handoff under two headers: 'Before startup' and 'When you get time.'","tips":["Two buckets are enough — urgency is the only sort key here.","Put times on the urgent items.","Keep the anytime list short or it buries itself."],"focus":["structure","clarity"],"placeholder":"BEFORE STARTUP: 1) Reset the jam counter or the line faults on start. 2) Retain samples to QC by 7:00."},
    {"id":"structure-mfg-early-25","level":"early","profession":"industrial","title":"The escalation after two silent work orders","scenario":"You've submitted two work orders for the leaking hydraulic fitting — ten days, no response — and now you're writing to your supervisor to escalate. The message needs structure or it reads as a complaint: history, current risk, specific ask.","task":"Write the escalation in 4 sentences: what you've submitted, what's changed, the risk, the ask.","tips":["Dates and work-order numbers make it a record, not a gripe.","'What's changed' is your urgency argument — the leak is worse.","Ask for something specific: maintenance on it this week."],"focus":["structure","impact"],"placeholder":"I've submitted two work orders for the hydraulic leak on press 4 (WO-2211 on 6/22, WO-2258 on 6/27) with no response."}
  ],
  "cut-to-the-bone": [
    {"id":"concise-mfg-early-01","level":"early","profession":"industrial","title":"The handoff paragraph, halved","scenario":"Your handoff note reads: 'So basically the labeler was kind of acting up for a while this afternoon, I think maybe around 2 or so, and I sort of got it going again by opening up the guard and clearing out some label backing that had built up in there over time.' One useful fact, forty filler words.","task":"Rewrite it in one sentence, keeping the time, the fault, and the fix.","tips":["'Basically,' 'kind of,' 'sort of' — all out.","Keep the three facts: 2:00, label backing buildup, cleared.","If a word doesn't help the next operator, it goes."],"focus":["concision","clarity"],"placeholder":"Labeler jammed around 2:00 — cleared label-backing buildup behind the guard; running fine since."},
    {"id":"concise-mfg-early-02","level":"early","profession":"industrial","title":"The hedge-free defect flag","scenario":"Your message to QC reads: 'I think some of these parts might be a little off on the diameter, possibly, if you get a chance you might want to maybe take a look at a few of them.' You measured them. They're off.","task":"Rewrite the flag in 1-2 sentences without a single hedge.","tips":["You have measurements — state them as facts.","'Might be a little off' hides a real out-of-spec reading.","The ask is a check, by a time — not 'if you get a chance.'"],"focus":["concision","precision"],"placeholder":"Diameters on the last rack are reading 0.4 mm under spec. Need a QC check before I run more."},
    {"id":"concise-mfg-early-03","level":"early","profession":"industrial","title":"The ten-second radio call","scenario":"Radio time is shared — the whole floor hears you, and long calls block the channel. You need maintenance at the depalletizer for a chain that's jumping sprockets. Your habit is thirty seconds of narration.","task":"Write the radio call in one sentence of 15 words or fewer.","tips":["Machine, symptom, ask — nothing else survives.","The channel is shared; brevity is courtesy.","Details go person-to-person once they arrive."],"focus":["concision","clarity"]},
    {"id":"concise-mfg-early-04","level":"early","profession":"industrial","title":"Cutting 'just wanted to reach out'","scenario":"Your message to the supervisor starts: 'Hey, sorry to bother you, just wanted to reach out and touch base real quick about something I noticed earlier that I thought you might want to know about.' Twenty-eight words, zero information.","task":"Delete the wind-up and write the first sentence as the news itself.","tips":["Meta-commentary announces the message instead of being it.","Start where the information starts.","Politeness lives in tone, not word count."],"focus":["concision","impact"],"placeholder":"The wash-down hose by line 2 is leaking at the wall fitting."},
    {"id":"concise-mfg-early-05","level":"early","profession":"industrial","title":"Redundant pairs on the report","scenario":"Your incident write-up says the floor was 'wet and slippery,' the response 'quick and immediate,' the fix 'full and complete,' and that you'll monitor it 'each and every shift.' Every pair can lose a word.","task":"Rewrite the four phrases as single words and use them in a 2-sentence version of the note.","tips":["Doubled words add weight, not meaning.","Pick the stronger word of each pair and cut the other.","Shorter reports get read; padded ones get skimmed."],"focus":["concision","clarity"]},
    {"id":"concise-mfg-early-06","level":"early","profession":"industrial","title":"The logbook without the weather","scenario":"Your log entry for a five-minute stop runs six sentences, including the mood of the shift and what you had planned before the stop. The log is a record of facts: time, event, action, status.","task":"Cut the entry to 2 sentences that keep only the facts.","tips":["Ask of each sentence: does the next reader need this?","Feelings and plans aren't log material.","Two tight sentences outlive six loose ones."],"focus":["concision","precision"]},
    {"id":"concise-mfg-early-07","level":"early","profession":"industrial","title":"The near-miss report on a diet","scenario":"Your near-miss draft is 200 words, and the facts — where, what almost happened, why — occupy about 40 of them. The rest is throat-clearing and repeated apology. Trimmed doesn't mean vague: keep the hazard sharp.","task":"Cut the report to 3-4 sentences that lose no facts.","tips":["Every fact stays: location, hazard, near-outcome, condition.","Every apology and repeat goes.","Short and specific beats long and mumbly — especially for safety."],"focus":["concision","precision"]},
    {"id":"concise-mfg-early-08","level":"early","profession":"industrial","title":"The defect tag with no room","scenario":"The defect tag has four short lines of space. Your draft description — 'these parts appear to have some kind of issue with the surface finish on the top face where it looks like something may have dragged across' — won't fit and shouldn't.","task":"Rewrite the description to fit one tag line: under 10 words.","tips":["Name the defect and location, drop the speculation.","'Appears to have some kind of issue' = 'scratched.'","Tags are read at arm's length in bad light — write for that."],"focus":["concision","precision"],"placeholder":"Drag scratches on top face — approx 60 pcs."},
    {"id":"concise-mfg-early-09","level":"early","profession":"industrial","title":"The apology-wrapped relief request","scenario":"Your break-relief request is 80% cushioning: 'I hate to ask, I know we're short today, and I totally understand if it's not possible, but if there's any way at some point...' The line lead reads a paragraph to find a five-minute ask.","task":"Cut the request to one sentence.","tips":["The ask is legitimate — cushioning implies it isn't.","One sentence: what, where, when.","Save the gratitude for after they say yes."],"focus":["concision","clarity"]},
    {"id":"concise-mfg-early-10","level":"early","profession":"industrial","title":"The play-by-play downtime note","scenario":"Your downtime note narrates every step: 'First I noticed the light, then I walked over, then I opened the panel, then I checked the sensor, then I called Dave, then Dave said...' The reader needs the cause, the fix, and the minutes — not your movements.","task":"Rewrite the note in 2 sentences: cause and duration, then fix.","tips":["Report the destination, not the journey.","Steps matter only when they change what someone does next.","'Then I' appearing twice is the signal to compress."],"focus":["concision","structure"],"placeholder":"Line down 25 min — infeed sensor misaligned after the guard was bumped."},
    {"id":"concise-mfg-early-11","level":"early","profession":"industrial","title":"'Is the order done?'","scenario":"Your supervisor texts: 'Is order 6690 done?' It is — finished twenty minutes ago, pallets staged. Your draft reply is five sentences that include the story of the afternoon.","task":"Write the reply in one sentence.","tips":["Yes, plus the one detail that helps: where it's staged.","A one-word question deserves a one-line answer.","Anything else can wait for the handoff note."],"focus":["concision","clarity"],"placeholder":"Done — all 12 pallets staged in lane 2."},
    {"id":"concise-mfg-early-12","level":"early","profession":"industrial","title":"The whiteboard has six inches","scenario":"The line whiteboard is where the next shift looks first, and you have six inches of space to warn them the reject gate is sticking and needs a tap before startup. Your instinct is to write small and cram.","task":"Write the whiteboard note in 8 words or fewer.","tips":["Big letters, few words — it's a sign, not a memo.","Verb-first: 'Tap reject gate before startup.'","If it needs more words, it needs a note, not the board."],"focus":["concision","impact"]},
    {"id":"concise-mfg-early-13","level":"early","profession":"industrial","title":"Six sentences to two","scenario":"Your text to your supervisor about the slow leak on the hydraulic press runs six sentences on a phone screen. Two of them carry the load: the leak is worse than yesterday, and you want maintenance before the weekend. Find them and cut the rest.","task":"Cut the text to those 2 sentences, keeping the ask.","tips":["Reread and star the two sentences that do the work.","Everything unstarred is a candidate for deletion.","On a phone, length is friction — respect the screen."],"focus":["concision","impact"]},
    {"id":"concise-mfg-early-14","level":"early","profession":"industrial","title":"The huddle update without filler","scenario":"Recorded, your huddle updates are half filler: 'um, so, yeah, basically, like I said, you know.' The content underneath is solid — the line ran to plan and the new fixture worked. Strip the packing material.","task":"Write the 2-sentence spoken update with zero filler words.","tips":["Write it as you'd want it heard, then say it that way.","A half-second pause replaces every 'um' — and sounds better.","Practicing one clean sentence beats apologizing for a messy one."],"focus":["concision","clarity"]},
    {"id":"concise-mfg-early-15","level":"early","profession":"industrial","title":"The bloated maintenance ticket","scenario":"Your ticket for the misfeeding bagger includes the history of the machine, your opinions of the last repair, and — buried in the middle — the actual symptom and when it started. Maintenance reads fifty tickets a week.","task":"Cut the ticket to 2-3 sentences: symptom, onset, frequency.","tips":["The last repair's story goes in conversation, not the ticket.","Symptom, when it started, how often — the diagnostic three.","Fifty-ticket readers reward the short ones with speed."],"focus":["concision","precision"],"placeholder":"Bagger misfeeds about 1 in 20 bags — film pulls crooked at the front roller. Started this morning."},
    {"id":"concise-mfg-early-16","level":"early","profession":"industrial","title":"Un-nominalize the log entry","scenario":"Your entry reads: 'Performed the implementation of an adjustment to the tensioner and conducted a verification of belt tracking.' Buried verbs: adjusted, verified. The nouns are wearing the verbs' clothes.","task":"Rewrite the entry with plain verbs, in one sentence.","tips":["'Performed an adjustment' = 'adjusted.'","'Conducted a verification' = 'verified' — or better, 'checked.'","Plain verbs shorten and sharpen at the same time."],"focus":["concision","clarity"],"placeholder":"Adjusted the tensioner and checked belt tracking — running true."},
    {"id":"concise-mfg-early-17","level":"early","profession":"industrial","title":"'Sort of' out loud","scenario":"Explaining the fault to the mechanic, you hear yourself: 'It sort of hesitates, kind of like a stutter, basically when it, like, indexes.' The observation is good — the indexing stutter — but it arrives wrapped in fog.","task":"Write the same observation as one clean spoken sentence.","tips":["Say the thing once, plainly: 'It stutters when it indexes.'","'Sort of' and 'kind of' soften facts that don't need softening.","A precise sentence gets a precise diagnosis started."],"focus":["concision","precision"]},
    {"id":"concise-mfg-early-18","level":"early","profession":"industrial","title":"The end-of-shift email, trimmed","scenario":"Your end-of-shift email to the supervisor runs twelve sentences. The news: hit 4,800 of 5,000 target, lost 40 minutes to a die change, tomorrow needs a glue delivery first thing. Everything else is narration.","task":"Cut the email to 3 sentences that keep those three facts.","tips":["One sentence per fact — output, downtime, tomorrow's need.","Chronology is for the logbook; the email is for decisions.","End on the item that needs action: the glue."],"focus":["concision","structure"],"placeholder":"Line 2 finished at 4,800 vs 5,000 — the 40-minute die change was the gap."},
    {"id":"concise-mfg-early-19","level":"early","profession":"industrial","title":"The favor inside the thank-you","scenario":"The mechanic stayed late yesterday to fix your conveyor, and now you need one more thing — a spare belt left at your station. Your draft is six sentences of thanks with the ask hidden in the last one.","task":"Rewrite in 2 sentences: genuine thanks, clear ask.","tips":["One sincere sentence of thanks — specific beats lengthy.","The ask stands alone where it can't be missed.","Gratitude and clarity aren't competitors."],"focus":["concision","clarity"]},
    {"id":"concise-mfg-early-20","level":"early","profession":"industrial","title":"Said three ways, needed once","scenario":"Your note says the same thing three times: 'The sensor needs cleaning daily. Make sure to clean the sensor every day. Don't forget the daily sensor cleaning.' Repetition feels emphatic to the writer and padded to the reader.","task":"Write it once, in a way that sticks — one sentence.","tips":["Say it once with a reason: that's what makes it stick.","'Every day' plus 'why' beats three repetitions.","If you fear it'll be missed, fix placement, not repetition."],"focus":["concision","impact"],"placeholder":"Clean the infeed sensor at shift start — dust buildup causes the false rejects we saw Tuesday."},
    {"id":"concise-mfg-early-21","level":"early","profession":"industrial","title":"The jam, compressed","scenario":"Asked what happened with the 2:00 jam, your written answer is nine sentences of cascading detail. The load-bearing facts: cartons bridged in the magazine, you cleared it, added a divider shim, and it hasn't recurred in two hours.","task":"Write the answer in 2 sentences keeping all four facts.","tips":["Four facts can share two sentences comfortably.","Cause and fix in one; result and status in the other.","Detail on request — that's what follow-up questions are for."],"focus":["concision","clarity"]},
    {"id":"concise-mfg-early-22","level":"early","profession":"industrial","title":"The call-in that rambles","scenario":"You're sick and calling in before the 6:00 shift. Nervous, your voicemail drafts keep growing: symptoms, apologies, guesses about tomorrow, more apologies. The supervisor needs three things: who, out today, station coverage note.","task":"Write the 2-sentence voicemail script.","tips":["Name, shift, out sick — first sentence.","Anything that helps coverage — your station, open tasks — second.","Prognosis for tomorrow only if you actually know it."],"focus":["concision","clarity"]},
    {"id":"concise-mfg-early-23","level":"early","profession":"industrial","title":"Shouting over the line","scenario":"The line is running and hearing protection is in — every spoken word costs effort. You need to tell your neighbor operator that QC is pulling samples at 3:00 and to leave the next full rack unwrapped. Say it in the fewest words that survive the noise.","task":"Write the shouted message in 12 words or fewer.","tips":["Nouns and verbs survive noise; connectives drown.","Two facts, two short phrases.","Confirm with a thumbs-up, not a paragraph."],"focus":["concision","clarity"],"placeholder":"QC pulls samples at 3:00 — leave next full rack unwrapped!"},
    {"id":"concise-mfg-early-24","level":"early","profession":"industrial","title":"Checklist notes, not essays","scenario":"The startup checklist has a notes column, and yours are full sentences: 'I checked the guard interlocks and found that all of them were functioning as expected.' The column is an inch wide. Notes are telegrams.","task":"Rewrite three checklist notes in 5 words or fewer each: interlocks OK, air pressure low then corrected, oil level topped up.","tips":["Telegram style: noun, status, action if any.","'Functioning as expected' = 'OK.'","Save sentences for the logbook when something's actually wrong."],"focus":["concision","precision"]},
    {"id":"concise-mfg-early-25","level":"early","profession":"industrial","title":"The suggestion in three sentences","scenario":"Your improvement suggestion — color-coding the changeover parts carts — is currently a full page. The review committee skims dozens of these. Problem, proposal, benefit: three sentences, then stop.","task":"Cut the suggestion to 3 sentences without losing the number that sells it.","tips":["A page proves effort; three sentences prove clarity.","Keep the one number that carries the case.","Stopping is a skill — resist the closing paragraph."],"focus":["concision","impact"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-mfg-early-01","level":"early","profession":"industrial","title":"'A lot of scrap' becomes a number","scenario":"You're reporting that the afternoon produced 'a lot of scrap, way more than usual.' You have the reject counter and the bin in front of you. 'A lot' is a feeling; the counter is a fact.","task":"Rewrite the report with the count, the time window, and the comparison to normal.","tips":["Read the counter — the number is right there.","'Way more than usual' becomes 'vs our normal 20-30.'","A number travels up the chain intact; 'a lot' mutates."],"focus":["precision","clarity"],"placeholder":"212 rejects between 12:00 and 16:00, versus our normal 20-30 for a full shift."},
    {"id":"precision-mfg-early-02","level":"early","profession":"industrial","title":"'Keeps jamming' gets a pattern","scenario":"Your work order says the cartoner 'keeps jamming.' Maintenance will ask: how often, which station, under what conditions? You've been watching it all day — you actually know: roughly every 45 minutes, always at the flap folder, mostly on the lightweight cartons.","task":"Rewrite the symptom line with frequency, location, and condition.","tips":["'Keeps' is doing the work three numbers should do.","Which station narrows the search from the whole machine to one spot.","The condition — lightweight cartons — might be the whole diagnosis."],"focus":["precision","audience"],"placeholder":"Cartoner jams roughly every 45 min, always at the flap folder, almost always on the 12-pack lightweight cartons."},
    {"id":"precision-mfg-early-03","level":"early","profession":"industrial","title":"'Running hot' against the setpoint","scenario":"You tell your supervisor the sealing bar is 'running hot.' The gauge reads 385°F; the setpoint is 350°F; spec allows ±15°F. Those three numbers turn a vibe into a report — and show it's out of the allowed band, not just warm.","task":"Write a 1-2 sentence report using the reading, the setpoint, and the tolerance.","tips":["Actual vs setpoint vs allowed band — the full triangle.","'Hot' could mean 5 over or 50 over; the number says which.","Out-of-band is the conclusion — state it, don't imply it."],"focus":["precision","clarity"],"placeholder":"Sealing bar is reading 385 against a 350 setpoint — 20 degrees past the +/-15 tolerance."},
    {"id":"precision-mfg-early-04","level":"early","profession":"industrial","title":"What, so what, now what","scenario":"Rejects have crept up four days straight: 18, 24, 31, 42. You could just forward the numbers, but numbers without a reading get filed. Give the fact, the meaning, and the action: What, So What, Now What.","task":"Write 3 sentences: the trend (what), the implication (so what), your proposed action (now what).","tips":["What: four numbers, four days — let them be seen.","So what: doubling every two days means real scrap money by Friday.","Now what: one concrete step — a die inspection, a material check."],"focus":["precision","impact"]},
    {"id":"precision-mfg-early-05","level":"early","profession":"industrial","title":"The skeptic test on 'bad film'","scenario":"You believe the new film supplier is causing the wrapper jams. Before you say it, run the skeptic's questions: How many jams on new film vs old? Same machine settings? Anything else change the same week? Your claim should survive all three.","task":"Write a 2-3 sentence claim about the film that a skeptic couldn't easily knock down.","tips":["Compare like with like: same machine, same settings, same product.","Count both sides: jams per roll on new film vs old.","Name the other thing that changed that week — and why it's not the cause."],"focus":["precision","impact"],"placeholder":"Since switching film Monday we've had 9 jams in 6 rolls; the last 6 rolls of the old film ran with 1. Same machine, same settings —"},
    {"id":"precision-mfg-early-06","level":"early","profession":"industrial","title":"'Earlier today' becomes a timestamp","scenario":"Your report says the leak 'started earlier today.' QC needs to bracket which product might be affected — 'earlier' could mean 6:00 or 11:30, a difference of hundreds of cases. You noticed it right after your 10:15 break.","task":"Rewrite the sentence with the time bracket QC can act on.","tips":["Give the bracket: fine at 10:00 check, leaking at 10:20.","The bracket defines the hold — vagueness holds more product than needed.","Tie times to fixed events: checks, breaks, changeovers."],"focus":["precision","impact"],"placeholder":"The leak started between my 10:00 check (dry) and 10:20 (dripping) —"},
    {"id":"precision-mfg-early-07","level":"early","profession":"industrial","title":"Describing the weird sound","scenario":"'The machine sounds weird' tells the mechanic nothing. You can pin it down: a metallic click, once per cycle, from the drive end, only under load, started two days ago. Each detail cuts the search space in half.","task":"Write a 2-sentence description covering sound type, timing, location, and condition.","tips":["Type of sound: click, grind, squeal, knock — pick the honest one.","Once per cycle vs continuous is a huge diagnostic split.","Under load vs always narrows it again."],"focus":["precision","audience"]},
    {"id":"precision-mfg-early-08","level":"early","profession":"industrial","title":"Checks: counted, not vibed","scenario":"Asked whether the hourly checks were good today, your instinct is 'yeah, mostly fine.' The sheet says: 7 checks done, 6 passed, 1 marginal at 13:00 that passed on recheck. That's a different — and better — answer.","task":"Write the answer using the actual counts from the sheet.","tips":["'Mostly fine' and '6 of 7, one marginal recheck-pass' feel very different to QC.","The marginal one is the interesting one — don't round it away.","Counted answers build trust in your uncounted ones."],"focus":["precision","clarity"],"placeholder":"7 of 7 checks done: 6 clean passes, one marginal at 13:00 that passed on recheck."},
    {"id":"precision-mfg-early-09","level":"early","profession":"industrial","title":"The hold needs edges","scenario":"You're putting product on hold after finding underweight bags. A hold without edges — 'this afternoon's production, roughly' — forces QC to quarantine everything. You can bound it: lot 7719, 12:30 to 14:00, roughly 40 cases, stacked on two pallets in lane 1.","task":"Write the 2-sentence hold message with lot, window, quantity, and location.","tips":["Four edges: lot, time window, count, location.","Tight edges protect good product from the hold.","'Roughly 40 cases' is fine — bounded beats falsely exact."],"focus":["precision","impact"],"placeholder":"Holding lot 7719, 12:30-14:00 production — about 40 cases on two pallets in lane 1."},
    {"id":"precision-mfg-early-10","level":"early","profession":"industrial","title":"The drifting torque driver","scenario":"Your electric torque driver feels like it's drifting. Feel isn't a report — but you ran five test cycles on the tester: 4.1, 4.3, 4.0, 4.4, 4.5 Nm against a 4.2 spec with ±0.2 allowed. Two of five outside the band, trending up.","task":"Write a 2-sentence report using the five readings and the spec.","tips":["List the readings — five numbers are stronger than any adjective.","State spec and band so the reader doesn't look them up.","Name the trend: drifting high, not just 'inconsistent.'"],"focus":["precision","clarity"]},
    {"id":"precision-mfg-early-11","level":"early","profession":"industrial","title":"'We're behind' by how much","scenario":"It's 1:00 and you tell your supervisor 'we're behind.' The board says: 2,100 units against a 2,600 pace target — 500 behind, which is about 50 minutes of production. And you know why: the morning's two die faults.","task":"Rewrite the update with the gap in units, the gap in time, and the cause.","tips":["Units behind AND minutes behind — one is production math, the other is intuition.","Attach the cause so the gap has a story.","Add the recovery view: can the gap close by end of shift?"],"focus":["precision","clarity"],"placeholder":"We're 500 units behind pace — about 50 minutes — from the two die faults this morning."},
    {"id":"precision-mfg-early-12","level":"early","profession":"industrial","title":"Saw versus assume","scenario":"The conveyor stopped and you found a crushed sensor bracket. Your draft says 'a forklift hit it.' You didn't see a forklift hit it — you saw a crushed bracket at forklift height with black rubber marks. Report what you saw; label your inference.","task":"Write 2 sentences: one of pure observation, one of clearly-labeled inference.","tips":["Observation: crushed bracket, height, rubber marks.","Inference gets a flag: 'consistent with' or 'likely.'","If the forklift driver disputes it, your report still stands."],"focus":["precision","clarity"],"placeholder":"The sensor bracket is crushed at about fork height with black rubber marks on it. That's consistent with a forklift strike, though I didn't see one."},
    {"id":"precision-mfg-early-13","level":"early","profession":"industrial","title":"The near-miss, pinned to the floor","scenario":"Your near-miss draft says a pallet 'almost fell near the racking.' Almost fell how far? Near which rack? The real picture: a top pallet slid six inches when the rack was bumped, at bay 12, directly over the pick path you were standing in.","task":"Rewrite the description with exact location, distance, and what was underneath.","tips":["'Near the racking' is a whole warehouse — bay 12 is a place.","Six inches of slide is measurable and chilling; 'almost fell' is neither.","What was underneath is the severity — say it plainly."],"focus":["precision","impact"]},
    {"id":"precision-mfg-early-14","level":"early","profession":"industrial","title":"'The pallet was heavy' in numbers","scenario":"You're flagging that the new pallet configuration is a lifting risk. 'The pallets are really heavy now' invites a shrug. The facts: cases went from 12 kg to 18 kg, stacked to 1.9 m — top row above shoulder height for most of the crew.","task":"Write the 2-sentence flag using the weights and the height.","tips":["Old weight vs new weight — the change is the story.","1.9 m means above-shoulder lifting; connect the number to the body.","Numbers make it an ergonomics issue, not a complaint."],"focus":["precision","impact"],"placeholder":"The new configuration takes cases from 12 kg to 18 kg, stacked to 1.9 m — the top row is an above-shoulder lift."},
    {"id":"precision-mfg-early-15","level":"early","profession":"industrial","title":"Downtime minutes, not vibes","scenario":"Your downtime entry says the line was down 'most of the morning.' The times you actually wrote on your pad: down 8:10-9:25, up until 10:05, down again 10:05-10:40. That's 110 minutes across two events — not 'most of the morning.'","task":"Write the downtime entry with the two windows and the total.","tips":["Two events, two windows — don't merge them into a blur.","Total the minutes; that's the number the report needs.","'Most of the morning' overstates it — and overstating cuts both ways."],"focus":["precision","structure"]},
    {"id":"precision-mfg-early-16","level":"early","profession":"industrial","title":"One insight from the hourly counts","scenario":"The hourly board reads: 620, 630, 610, 640, 380, 615, 605, 590. Forwarding eight numbers isn't reporting. One of them is a story — the 380 lines up with the hour after the material changeover.","task":"Write 2 sentences: the one insight from the data, then the supporting numbers.","tips":["Lead with the reading, not the data: 'we lose a third of an hour after changeovers.'","The other seven numbers prove normal — one clause covers them.","One insight per message; a second insight is a second message."],"focus":["precision","impact"],"placeholder":"We lose about a third of the hour after each material changeover — 380 units against a 600-630 norm."},
    {"id":"precision-mfg-early-17","level":"early","profession":"industrial","title":"The defect, located on the part","scenario":"Your tag says the parts have 'a mark.' Where, how big, how many? Better: a 5 mm gouge on the top face near the mounting hole, same spot every part, 100% of parts since roughly 13:00. Same-spot-every-part points straight at tooling.","task":"Rewrite the description with location on the part, size, and rate.","tips":["Same spot every time vs random spots is the key diagnostic fact.","Size it against something if you can't measure: 'pencil-eraser wide.'","Rate: every part, 1 in 10, occasional — pick the honest one."],"focus":["precision","clarity"]},
    {"id":"precision-mfg-early-18","level":"early","profession":"industrial","title":"Retiring 'always' and 'never'","scenario":"Frustrated, you've drafted: 'The stacker always faults on the tall cases and maintenance never fixes it.' At the meeting, one counterexample kills your credibility. The defensible version: faulted on 3 of the last 4 tall-case runs; two work orders in six weeks, both closed without the fault recurring... until now.","task":"Rewrite the two claims in numbers that survive one counterexample.","tips":["'Always' dies to one exception; '3 of the last 4' doesn't.","Check the work-order history before characterizing it.","Precise complaints get fixes; absolute ones get eye-rolls."],"focus":["precision","impact"]},
    {"id":"precision-mfg-early-19","level":"early","profession":"industrial","title":"The scale check with readings","scenario":"You think the floor scale is reading light. Saying so without numbers starts an argument. You put the 20 kg test weight on it three times: 19.4, 19.5, 19.4. Now it's not an opinion.","task":"Write the 2-sentence report with the test method and the three readings.","tips":["Name the reference: the certified 20 kg test weight.","Three consistent readings rule out a fluke.","End with the implication: everything weighed today is suspect light."],"focus":["precision","clarity"],"placeholder":"The floor scale reads light: the 20 kg test weight shows 19.4, 19.5, 19.4 across three tries."},
    {"id":"precision-mfg-early-20","level":"early","profession":"industrial","title":"Sizing the leak","scenario":"'There's a leak on press 4' could mean a weep or a stream. You watched it: about a drip per second at the fitting, a puddle the size of a dinner plate after an hour, and it doubled since yesterday. Those three facts set the urgency honestly.","task":"Write a 2-sentence report that sizes the leak and its trend.","tips":["Rate, accumulation, trend — the three sizes of any leak.","Household comparisons work: dinner plate, coffee cup.","The trend is the urgency: stable weeps wait, doubling ones don't."],"focus":["precision","impact"]},
    {"id":"precision-mfg-early-21","level":"early","profession":"industrial","title":"The fault code, in sequence","scenario":"You tell maintenance the palletizer 'errored out.' The screen showed E-217, then the hoist stopped mid-lift, then E-108 after the reset attempt. The exact codes in the exact order may be the whole diagnosis — if you report them.","task":"Write the fault report with both codes and the sequence of events.","tips":["Copy codes exactly — E-217 and E-217A can be different worlds.","Order matters: first fault, then what the reset produced.","Note where the machine physically stopped; the screen isn't the whole story."],"focus":["precision","audience"],"placeholder":"Palletizer threw E-217 and stopped mid-lift with a load on the hoist. Reset attempt gave E-108."},
    {"id":"precision-mfg-early-22","level":"early","profession":"industrial","title":"Handoff quantities, counted","scenario":"Your handoff says there's 'plenty of material to get through the night.' You can count it: 14 pallets of bottles, 6 rolls of film, 2 drums of glue — and glue burns a drum a shift, so 'plenty' is actually 'tight on glue.' Counting changed the message.","task":"Rewrite the materials line with counts and the one item that's tight.","tips":["Count what's there; compare against burn rate.","'Plenty' hid a glue problem — numbers found it.","Flag the constraint item by name; the rest can be a list."],"focus":["precision","clarity"],"placeholder":"Materials: 14 pallets bottles, 6 rolls film — both comfortable. Glue is tight: 2 drums and we burn one per shift."},
    {"id":"precision-mfg-early-23","level":"early","profession":"industrial","title":"'The fix worked' — for how long?","scenario":"Maintenance asks if their morning fix on the diverter held. 'Seems fine now' is weak evidence. The strong version: 400+ cycles since 9:30 without a fault, including two full-speed runs — the exact conditions that used to trigger it.","task":"Write the 2-sentence answer with cycle count and conditions tested.","tips":["Duration of success in cycles or hours, not 'seems fine.'","Say whether the old trigger conditions occurred — that's the real test.","If it hasn't been tested under load yet, say that too."],"focus":["precision","clarity"]},
    {"id":"precision-mfg-early-24","level":"early","profession":"industrial","title":"The changeover estimate with parts","scenario":"Asked how long until the changeover's done, you're tempted to say 'almost there.' The honest breakdown: rails are set (done), guarding needs 15 minutes, first-piece check takes 10 once QC arrives. 'Almost there' could be 25 minutes or an hour depending on QC.","task":"Write the estimate broken into its parts, flagging the QC dependency.","tips":["Estimate the parts, not the whole — parts are checkable.","Flag the dependency you don't control as its own line.","'25 minutes after QC arrives' is honest; 'almost there' isn't."],"focus":["precision","structure"],"placeholder":"Rails are done. Guarding is 15 more minutes, then a 10-minute first-piece check — but that starts only when QC gets here."},
    {"id":"precision-mfg-early-25","level":"early","profession":"industrial","title":"Before and after the speed change","scenario":"The line speed was bumped up Tuesday and you sense quality slipped. Sense isn't evidence. The check sheets say: rejects averaged 22 a shift the week before, 41 a shift the three days since. Same product, same crew.","task":"Write a 2-3 sentence report comparing before and after, controlling for what stayed the same.","tips":["Before-number and after-number, same units, side by side.","Name what stayed constant — product, crew — so speed stands alone.","Suggest the test: a day back at old speed settles it."],"focus":["precision","impact"]}
  ],
  "executive-presence": [
    {"id":"presence-mfg-early-01","level":"early","profession":"industrial","title":"The menu instead of a pick","scenario":"Your supervisor asks which changeover order to run tomorrow — labels first or film first. You've run it both ways and film-first saves ten minutes, but your draft lays out both options evenly and ends with 'whichever you think.'","task":"Rewrite the reply to own a clear recommendation, with the alternative as support.","tips":["State your pick and the reason in the first sentence.","Mention the other option and why you'd pass on it.","You ran the trial — the recommendation is yours to make."],"focus":["impact","structure"],"placeholder":"Run film first — it saved us ten minutes both times we tried it. Labels-first works, but the film cool-down eats the gain."},
    {"id":"presence-mfg-early-02","level":"early","profession":"industrial","title":"Fact and opinion, tangled","scenario":"Your note about this morning's late resin delivery reads: 'Material was late again, obviously the warehouse doesn't care about our line.' Your supervisor needs the facts separated from your read so they can act on both.","task":"Rewrite the note with the facts stated first and your judgment labeled as your judgment.","tips":["Facts first, plainly: what arrived, when, how often it's happened.","Then your read, marked as a read — 'my take is...'","Blending the two makes both look less credible."],"focus":["precision","impact"],"placeholder":"Fact: the resin arrived 40 minutes late — third time this week. My read: the pickup time needs to move, not the crew."},
    {"id":"presence-mfg-early-03","level":"early","profession":"industrial","title":"The update with no map","scenario":"You're giving your supervisor a verbal update covering the machine status, a staffing gap for tomorrow, and a decision you need on the die change. You launch straight in with no map, so they can't tell how long you'll go or what's coming.","task":"Write the opening sentence that signposts the three points before you dive in.","tips":["Tell them the shape first: 'three quick things.'","Name the topics in one breath, then take them in order.","A signpost reads as command of the material."],"focus":["structure","impact"],"placeholder":"Three quick things: line status, a staffing gap tomorrow, and one decision I need on the die change."},
    {"id":"presence-mfg-early-04","level":"early","profession":"industrial","title":"The hedge stack","scenario":"Your message to maintenance reads: 'I think the infeed sensor might maybe be drifting a little, possibly? It kind of seems like the rejects could be related.' Every hedge shaves credibility off an observation you're actually sure about.","task":"Rewrite it as one clean sentence that says what you observe without the hedges.","tips":["Cut 'I think,' 'might,' 'kind of' — keep one honest qualifier at most.","State the evidence: what you measured or counted.","Confidence in what you SAW is not arrogance."],"focus":["concision","impact"],"placeholder":"The infeed sensor is drifting — false rejects have doubled since Monday and re-aiming it clears them for an hour."},
    {"id":"presence-mfg-early-05","level":"early","profession":"industrial","title":"'I'm just an operator, but...'","scenario":"The process engineer is at your press investigating vibration. You've noticed it only started after the rebuild and only above a certain speed — real information. Your opener is 'I'm just an operator, but...' which invites them to discount everything after it.","task":"Rewrite what you'd say with the self-discount removed and your observation stated as the evidence it is.","tips":["Your hours on this machine ARE the credential — no apology needed.","Lead with the observation, specific and datable.","Let the engineer weigh it; don't pre-shrink it for them."],"focus":["impact","clarity"],"placeholder":"I run this press eight hours a day — the vibration is new since the rebuild, and it only shows up above 60 cycles a minute."},
    {"id":"presence-mfg-early-06","level":"early","profession":"industrial","title":"The status that sounds like a question","scenario":"At the huddle your line status keeps drifting upward at the end of every sentence — 'we ran to plan? rejects were normal?' — like you're asking whether it's true. The words are fine; the delivery undercuts them.","task":"Write the 2-sentence status as flat statements, worded so they can only be said with a period.","tips":["Short declarative sentences are hard to say as questions.","End on a fact or a number, not a trailing qualifier.","Say it out loud once — land each sentence down, not up."],"focus":["impact","concision"]},
    {"id":"presence-mfg-early-07","level":"early","profession":"industrial","title":"The auditor at your station","scenario":"An external auditor stops at your station and asks you to walk them through what you check each hour. This is normal — you know this cold — but nerves push people into rambling or reciting the poster on the wall.","task":"Write the 3-4 sentence answer you'd give, signposted so the auditor can follow it.","tips":["Open with the count: 'every hour I check three things.'","Name each check and where it's recorded.","Plain first-person beats reciting the procedure doc."],"focus":["structure","audience"],"placeholder":"Every hour I check three things: fill weight, cap torque, and label placement. The weights go on the log sheet here, and anything out of spec goes to the red bin and a call to QC."},
    {"id":"presence-mfg-early-08","level":"early","profession":"industrial","title":"The plant manager's walk-by","scenario":"The plant manager walks your line and asks 'how's it going?' The reflex answers — 'fine' or a nervous data dump — both waste the moment. A real answer has one solid fact and one thing you're on top of.","task":"Write the 2-sentence answer you'd give: status with a number, plus the one thing you're watching.","tips":["One real number makes 'fine' credible.","Naming what you're watching shows you run the line, not just stand at it.","Two sentences — it's a walk-by, not a review."],"focus":["audience","impact"],"placeholder":"Running at 98% of rate and on pace for the order. I'm watching the labeler — it jammed twice this morning and I've got maintenance coming at the break."},
    {"id":"presence-mfg-early-09","level":"early","profession":"industrial","title":"'It'll take as long as it takes'","scenario":"Your supervisor asks how long the rework on the mislabeled cases will take. Your honest instinct is 'as long as it takes,' but that leaves them unable to plan anything. Owning an estimate — with a checkpoint — is the stronger answer.","task":"Write a 1-2 sentence answer that commits to a time and names when you'd flag a slip.","tips":["Give a number even if it's rough — 'about two hours.'","Build in the checkpoint: 'if it's tracking long, I'll flag you at noon.'","An owned estimate with a flag beats a safe shrug."],"focus":["precision","impact"],"placeholder":"About two hours — done by 1:00. If it's tracking longer than that, I'll flag you at noon."},
    {"id":"presence-mfg-early-10","level":"early","profession":"industrial","title":"The containment plan you won't own","scenario":"You found short-fills going back maybe an hour. You know what containment should look like — hold the pallet, pull samples, re-check the filler — but your message to your supervisor just describes the problem and waits to be told.","task":"Write a 2-3 sentence message that states the problem and OWNS the recommended containment steps.","tips":["Problem in sentence one, your recommended steps in sentence two.","Use 'I recommend' or 'I've started' — not 'should someone maybe.'","Invite the veto: 'unless you want it handled differently.'"],"focus":["impact","structure"],"placeholder":"Short-fills on line 2, going back about an hour. I've held the pallet and pulled ten samples for QC — I recommend we re-verify the filler before restarting."},
    {"id":"presence-mfg-early-11","level":"early","profession":"industrial","title":"Your minute at the toolbox talk","scenario":"You asked for a minute at the toolbox talk to flag the blind corner by the stretch wrapper. Your draft opens with 'sorry to take up time, this is probably nothing.' If it was nothing you wouldn't be raising it — the apology tells the crew to tune out.","task":"Write the 2-3 sentences you'd say, opening with the hazard instead of an apology.","tips":["First sentence: the hazard and where it is.","Second: what you want people to do differently.","Skip the apology — safety time is what the talk is FOR."],"focus":["clarity","impact"]},
    {"id":"presence-mfg-early-12","level":"early","profession":"industrial","title":"'They did a lazy job'","scenario":"The conveyor fault came back two hours after maintenance closed the work order. Your draft note to your supervisor says the mechanic 'did a lazy job.' That's a judgment doing the work facts should do — and it starts a war you don't need.","task":"Rewrite as facts first, then your labeled read on what should happen next.","tips":["Facts: fault cleared at 9:00, returned at 11:05, same symptom.","Your read, labeled: the fix didn't hold, it needs a deeper look.","Attack the problem's persistence, not the person."],"focus":["precision","clarity"],"placeholder":"The conveyor fault returned at 11:05, two hours after the work order closed — same symptom. My read: the fix treated the surface issue and it needs a deeper look."},
    {"id":"presence-mfg-early-13","level":"early","profession":"industrial","title":"'Should be OK' versus verified","scenario":"You finished putting line 3 back together after the jam. Your message to the supervisor says it 'should be OK now.' 'Should be' makes them wonder what you didn't check. You did check — say what.","task":"Rewrite the status so it states what was verified instead of hoping out loud.","tips":["Replace 'should be' with what you actually confirmed.","Name the verification: test run, count, guards back on.","If something is NOT verified, say that too — precisely."],"focus":["precision","clarity"],"placeholder":"Line 3 is back up: guards on, test run of 20 parts all in spec. One thing I haven't verified — the reject gate under full speed."},
    {"id":"presence-mfg-early-14","level":"early","profession":"industrial","title":"Ninety seconds for the tour group","scenario":"A customer tour stops at your station and your supervisor says 'tell them what happens here.' You know everything about this station — which is the problem. Ninety seconds needs a shape, not everything.","task":"Write a 3-4 sentence walkthrough with a clear shape: what comes in, what you do, what leaves.","tips":["Pick the frame: in, transform, out.","One quality point shows the craft — 'every unit gets checked for X.'","Leave out anything a visitor can't picture."],"focus":["structure","audience"],"placeholder":"Parts come to me from the molder, and my job is the final assembly and check. Every unit gets a torque test before it leaves —"},
    {"id":"presence-mfg-early-15","level":"early","profession":"industrial","title":"Disagreeing with the mechanic","scenario":"The mechanic says the recurring fault is the sensor and keeps replacing it. You've noticed it comes back within an hour of every belt rethread — you think it's belt tracking. You're junior to nobody on what this machine does all shift.","task":"Write the 2-3 sentences you'd say: your different read, with the evidence, without heat.","tips":["Lead with the pattern you observed, dated and specific.","Frame it as evidence to weigh, not a verdict on their skill.","Propose the test that would settle it."],"focus":["precision","impact"],"placeholder":"I don't think it's the sensor — the fault comes back within an hour of every belt rethread, and the last two sensors tested fine after swap. Worth watching the tracking on the next rethread?"},
    {"id":"presence-mfg-early-16","level":"early","profession":"industrial","title":"'The wrong film got loaded'","scenario":"You loaded 500 ml film on the 750 ml run and caught it at the first check. Your incident note says 'the wrong film got loaded' — passive voice with nobody in it. Everyone will know anyway; hiding in grammar just looks evasive.","task":"Rewrite the note in active voice, owning the error and stating the catch and the fix.","tips":["'I loaded' — own the verb.","The catch is part of the story: your check worked.","Plain ownership reads stronger than passive fog."],"focus":["clarity","impact"],"placeholder":"I loaded the 500 ml film on the 750 run and caught it at the first hourly check — 200 units quarantined, correct film verified before restart."},
    {"id":"presence-mfg-early-17","level":"early","profession":"industrial","title":"Data with a stance","scenario":"You're presenting the reject numbers at the weekly quality meeting: rejects doubled the day the new resin lot started. Your draft just reads the numbers out and stops. The room needs your position on what the numbers mean.","task":"Write 2-3 sentences: the numbers, then the position you take on them, then the test you propose.","tips":["Numbers first, tight: doubled, from when.","Then your stance: 'I think the resin is the variable.'","End with the test that would prove or kill your theory."],"focus":["impact","structure"],"placeholder":"Rejects doubled the day the new resin lot started, and nothing else changed — same crew, same settings. I think the resin is the variable, and one shift back on the old lot would prove it."},
    {"id":"presence-mfg-early-18","level":"early","profession":"industrial","title":"The engineer asks what you think","scenario":"The engineer redesigning the infeed asks you directly: 'You run this every day — what do you think of the new guide rails?' You have a real answer: they're better at speed but jam on the short bottles. Vague politeness would waste the only floor input they'll get.","task":"Write the 2-3 sentence answer: your honest assessment, both sides, specific.","tips":["Give the genuine verdict, not the polite one.","Split it cleanly: better at X, worse at Y.","Specifics make it usable — name the product that jams."],"focus":["audience","impact"],"placeholder":"At full speed they're a real improvement — no more spinouts. But the short 250 ml bottles jam at the transition about once an hour, and they didn't before."},
    {"id":"presence-mfg-early-19","level":"early","profession":"industrial","title":"The wobbly maintenance ask","scenario":"The trim die needs changing before it starts making scrap. Your draft to the supervisor reads: 'Not sure if this is a big deal, but at some point we might want to think about maybe scheduling a die change?' The wobble buries a call you're right about.","task":"Rewrite as a confident recommendation with a proposed date.","tips":["'I recommend we change the die' — say the thing.","Anchor it to evidence: the edge trend across shifts.","Propose the slot: 'Thursday's changeover window.'"],"focus":["impact","clarity"],"placeholder":"I recommend we change the trim die at Thursday's changeover. Edge finish has gotten worse three shifts running — we'll be cutting scrap by next week if we wait."},
    {"id":"presence-mfg-early-20","level":"early","profession":"industrial","title":"Calibrated confidence on the target","scenario":"Your supervisor asks if the line will hit today's number. The honest answer is probably — you're at 92% of pace with your stronger half of the shift ahead, but a film splice could cost an hour. 'Hope so' undersells it; 'definitely' oversells it.","task":"Write a 2-sentence answer that gives the confident call AND the one risk with a check-in time.","tips":["Lead with the call: 'we'll hit it.'","Name the single risk that could change it — just one.","Attach a time you'll know: 'I'll confirm by 2:00.'"],"focus":["precision","impact"],"placeholder":"We'll hit it — 92% of pace now and the afternoon is our stronger run. The one risk is the film splice on roll change; I'll know by 2:00 and flag you if it goes sideways."},
    {"id":"presence-mfg-early-21","level":"early","profession":"industrial","title":"The two-part radio call","scenario":"You need to tell your supervisor two things on the radio: the jam is cleared and running, and you need film delivered before 3:00. Radio traffic gets stepped on — an unsignposted call loses its second half.","task":"Write the radio call, signposted so both parts land.","tips":["Open with the count: 'two things from line 4.'","Good news first and short, the ask second and specific.","End on the ask — it's the part that needs action."],"focus":["structure","concision"],"placeholder":"Two things from line 4: the jam is cleared and we're running, and I need two rolls of film delivered before 3:00."},
    {"id":"presence-mfg-early-22","level":"early","profession":"industrial","title":"The suggestion form that hides its point","scenario":"You're filling in the improvement suggestion form. Your idea — a shadow board for changeover tools — is in paragraph three, after two paragraphs about how you got the idea. The committee skims dozens of these; buried ideas die.","task":"Rewrite the opening so the proposal and its payoff are the first sentence.","tips":["Sentence one: the proposal and the minutes it saves.","The origin story can go last or go entirely.","Write for a skimmer — assume they read one sentence."],"focus":["structure","impact"],"placeholder":"Proposal: a shadow board for the changeover tools at line 2 — we lose 10-15 minutes per changeover hunting for them."},
    {"id":"presence-mfg-early-23","level":"early","profession":"industrial","title":"'Sorry, quick dumb question'","scenario":"You need to ask the engineer which spec revision applies to today's lot — a completely legitimate question. Your draft opens 'Sorry, quick dumb question, you're probably busy...' The framing invites them to treat both you and the question as small.","task":"Rewrite the question with the preamble deleted.","tips":["Just ask — a clear question needs no permission slip.","Include the two candidates so they can answer in one word.","'Dumb question' teaches people to expect dumb questions from you."],"focus":["concision","impact"],"placeholder":"Which spec applies to lot 8812 — the sheet at the station or revision C in the binder?"},
    {"id":"presence-mfg-early-24","level":"early","profession":"industrial","title":"The report written in apologies","scenario":"Your end-of-shift report reads like a confession: 'unfortunately we only made 4,100... I'm afraid the jam cost us... sadly the last pallet...' The facts are fine — a jam happened, you recovered most of it — but the tone reads like failure.","task":"Rewrite the report as plain facts, no apology words, with the recovery visible.","tips":["Delete 'unfortunately,' 'I'm afraid,' 'sadly' — the facts don't need mourners.","State the number, the cause, the recovery.","A jam is an event, not a sin — write it that way."],"focus":["clarity","impact"],"placeholder":"4,100 of 4,400 units — a 40-minute jam on the labeler cost the difference. Jam cleared, root cause tagged for maintenance, line handed over running at rate."},
    {"id":"presence-mfg-early-25","level":"early","profession":"industrial","title":"'We'll try' at the huddle","scenario":"At the huddle your supervisor asks if your line can absorb the extra 500 units today. Your reflex is 'we'll try.' 'Try' commits to nothing and makes you sound unsure of your own line. You actually know the answer: yes, if the changeover stays on time.","task":"Write the 1-2 sentence commitment you'd say instead, with the condition and a flag time.","tips":["Commit to the thing: 'we'll run the extra 500.'","Name the one condition it depends on.","Give the flag time so 'yes' has a safety valve."],"focus":["precision","impact"],"placeholder":"We'll run the extra 500 — as long as the 1:00 changeover stays on schedule. If it slips, I'll tell you by 1:30 what we can still do."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-mfg-early-01","level":"early","profession":"industrial","title":"The yes/no you owe first","scenario":"Your supervisor asks point-blank at the line: 'Will order 6620 finish by end of shift?' You start explaining the morning's material delay. They asked a yes/no question — the explanation is only useful after the answer.","task":"Write the spoken answer that gives the yes/no first, then one qualifier.","tips":["First word: yes or no.","One condition may ride along — keep it to a clause.","Making them wait for the answer reads as a dodge."],"focus":["clarity","impact"],"placeholder":"Yes — done by 6:00, as long as the film delivery lands by 3:00 like promised."},
    {"id":"pressure-mfg-early-02","level":"early","profession":"industrial","title":"'Are you sure you counted right?'","scenario":"You reported the shipment 300 units short. Your supervisor pushes back: 'Are you sure you counted right?' Bristling undercuts you; folding undercuts you worse. What settles it is your method.","task":"Write a 2-3 sentence reply that answers the doubt with how you counted, not defensiveness.","tips":["Take the question as a fair check, not an insult.","Give the method: counted twice, scanner-verified, same result.","Offer the recount if they want it — confidence isn't threatened by one."],"focus":["precision","impact"],"placeholder":"Fair to check — I counted the pallets twice and ran the scanner totals, and both came to 300 short. Happy to do a third count with you watching."},
    {"id":"pressure-mfg-early-03","level":"early","profession":"industrial","title":"The honest 'I don't know'","scenario":"The auditor asks how often the check-weigher gets calibrated. You don't know the interval off the top of your head — but you know exactly where it's written. Guessing in an audit is how small gaps become findings.","task":"Write the 2-sentence answer: a clean 'I don't know,' then the path to the answer.","tips":["Say you don't have it to hand — no padding, no guessing.","Point to where the answer lives and get it.","'Let me show you the log' is a GOOD audit answer."],"focus":["clarity","impact"],"placeholder":"I don't know the interval off the top of my head — it's on the calibration log right there on the scale. Give me thirty seconds and I'll show you."},
    {"id":"pressure-mfg-early-04","level":"early","profession":"industrial","title":"'Why is this line down AGAIN?'","scenario":"Your supervisor arrives hot: 'Why is this line down AGAIN?' There's a barb in the question. Answering the barb starts an argument; answering the fact gets the line running. The fact: same photo-eye as Tuesday, maintenance already called.","task":"Write the calm 1-2 sentence answer that takes the question at face value and skips the bait.","tips":["Answer the literal question: what's down, why, status.","Include the recovery: who's on it, running by when.","Match facts to their heat — not heat to their heat."],"focus":["clarity","impact"],"placeholder":"Same photo-eye as Tuesday — maintenance is on the way and I expect us running by 10:15. I've asked them to bring a replacement this time, not another re-aim."},
    {"id":"pressure-mfg-early-05","level":"early","profession":"industrial","title":"Two questions in one breath","scenario":"Your supervisor fires two questions at once: 'Where are we on the order, and did the torque issue from yesterday come back?' Answering them tangled together muddles both. Taking them one at a time, labeled, keeps you in control.","task":"Write the spoken answer that takes the two questions in order, each labeled.","tips":["Signpost: 'On the order... On the torque...'","Answer each fully before starting the next.","Order them: the one they care most about first."],"focus":["structure","clarity"],"placeholder":"On the order: 60% done, on pace for end of shift. On the torque: no — it's held in spec all morning, I've been checking every half hour."},
    {"id":"pressure-mfg-early-06","level":"early","profession":"industrial","title":"Interrupted mid-answer","scenario":"You're explaining the downtime cause at the huddle and a senior operator cuts in with their own theory. Your instinct is either to go silent or to talk over them. Neither finishes your point — which happens to be right.","task":"Write the sentence you'd use to take the thread back calmly and land your point.","tips":["Let them finish, then re-enter with a hook: 'that's part of it — the piece that changes things is...'","Restate your point shorter than before, not longer.","Calm persistence reads as confidence; volume reads as panic."],"focus":["impact","concision"]},
    {"id":"pressure-mfg-early-07","level":"early","profession":"industrial","title":"'Who told you to run it that way?'","scenario":"QC found parts off-nominal and someone asks, sharply: 'Who told you to run it at that speed?' The setup card told you — and the line lead confirmed it. There's a way to answer that's accurate without sounding like you're throwing anyone under a bus.","task":"Write a 1-2 sentence answer that states your basis factually, without deflecting or accusing.","tips":["Cite the document first — 'the setup card for this product says 60.'","People come second and neutrally: 'and I confirmed it at handoff.'","You're establishing the trail, not assigning blame."],"focus":["precision","clarity"],"placeholder":"The setup card for this product specifies 60 a minute, and I confirmed it at handoff. If the card's wrong, that's worth fixing before the next run."},
    {"id":"pressure-mfg-early-08","level":"early","profession":"industrial","title":"'How long until it's back up?'","scenario":"The line is down and your supervisor needs a time. You genuinely don't know yet — it's either the fuse (20 minutes) or the drive (2 hours). A fake-precise answer will be wrong; 'no idea' is useless. The honest range with a decision point is the pro answer.","task":"Write the 2-sentence answer: the range, and when you'll know which end of it you're on.","tips":["Give both scenarios with their times — that IS the honest answer.","Name when the fork resolves: 'I'll know within ten minutes.'","Commit to update them at that point without being asked."],"focus":["precision","impact"],"placeholder":"Best case 20 minutes if it's the fuse; if it's the drive, more like two hours. Maintenance will know which within ten minutes and I'll radio you the moment they do."},
    {"id":"pressure-mfg-early-09","level":"early","profession":"industrial","title":"QC questions your log","scenario":"QC calls you over: two entries on your check sheet look identical to the decimal, and they're asking — politely but pointedly — whether you actually took both readings. You did; the product was just that stable. Defensiveness would look like guilt.","task":"Write the 2-3 sentence answer: the direct claim, the supporting detail, the offer to verify.","tips":["Answer the actual doubt head-on: 'I took both readings.'","Add the texture only a real reading would have — time, position, anything checkable.","Offer the live re-check; nothing answers doubt like 'watch me do it.'"],"focus":["precision","audience"],"placeholder":"I took both readings — 10:00 and 11:00, same three-bottle pull each time. The line didn't drift, which is why they match. Want to watch the noon check with me?"},
    {"id":"pressure-mfg-early-10","level":"early","profession":"industrial","title":"The loaded question","scenario":"After the defect escape, someone asks: 'Don't you think you should have caught this sooner?' It's a question shaped like an accusation. Arguing the shape wastes breath — answering the substance, with the actual check timeline, is the strong move.","task":"Write a 2-3 sentence answer that addresses the substance and states what would catch it faster.","tips":["Answer with the timeline: when the check runs, when it passed, when it failed.","Skip defending your character — the facts do that.","Pivot forward: what checking sooner would actually require."],"focus":["clarity","impact"],"placeholder":"The check that catches this runs every two hours — it passed at noon and failed at 2:00, so the escape window is inside that gap. If we want it caught faster, the check interval has to shorten, and I'd support that."},
    {"id":"pressure-mfg-early-11","level":"early","profession":"industrial","title":"Asked about a line you don't run","scenario":"At the huddle the production manager asks you how line 5's changeover went. You run line 3 — you only know secondhand fragments about 5. Bluffing an answer risks being wrong in front of everyone; a clean boundary plus a pointer is fine.","task":"Write the 1-2 sentence answer: what you can speak to, and who can speak to the rest.","tips":["Answer for your patch first if it's relevant.","Draw the boundary without apology: 'I can't speak to line 5.'","Point to the person who can — that's helping, not dodging."],"focus":["clarity","concision"],"placeholder":"I can only speak to line 3 — we ran to plan. For line 5's changeover you'd want Dana; she ran it."},
    {"id":"pressure-mfg-early-12","level":"early","profession":"industrial","title":"The supervisor arrives angry","scenario":"The shift missed target and your supervisor is venting at you, voice raised. Some of it is fair — the jam was on your line — and some isn't. Matching the heat loses; going silent looks like you have nothing. Facts, ownership, plan.","task":"Write the 2-3 sentences you'd say once there's a gap to speak into.","tips":["Own your piece precisely: 'the jam on my line cost 40 minutes — that's mine.'","Correct the record calmly where it's wrong, with a number.","End on the plan, not the apology."],"focus":["clarity","impact"]},
    {"id":"pressure-mfg-early-13","level":"early","profession":"industrial","title":"Rapid-fire after the near-miss","scenario":"The safety coordinator is asking quick questions about the forklift near-miss: where were you standing, was the alarm sounding, what could you see? Nerves push people to answer more than was asked and speculate into the gaps. Precision matters here — this becomes a record.","task":"Write answers to those three questions, each one sentence, no speculation.","tips":["Answer exactly what was asked, then stop.","'I don't know' is a complete answer where it's true.","Observed facts only — no guessing at what the driver saw."],"focus":["concision","precision"],"placeholder":"I was at the line 5 corner, about a meter from the racking. I didn't hear the alarm over the grinder — it may have been sounding. I could see the forks but not the driver."},
    {"id":"pressure-mfg-early-14","level":"early","profession":"industrial","title":"'Can you commit to that right now?'","scenario":"The planner catches you at the line: 'Can you commit to finishing 7734 by Friday, right now?' You can't — not without checking the die schedule. Pressure to answer on the spot is real, but a bounded 'I'll know by 3:00' beats a commitment you might break.","task":"Write the 1-2 sentence answer that declines to guess and commits to a firm answer by a time.","tips":["Don't let urgency extract a number you can't stand behind.","Name what you need to check and how long that takes.","Then be early with the answer you promised."],"focus":["clarity","precision"],"placeholder":"I can't commit without checking the die schedule — give me until 3:00 and I'll give you a firm yes or a firm date."},
    {"id":"pressure-mfg-early-15","level":"early","profession":"industrial","title":"The engineer asks why you changed the setting","scenario":"The process engineer notices the heat setpoint is 5 degrees above the card and asks why — direct, not hostile, but it lands like a challenge. You had a reason: seal failures at the card setting every cold morning. Defensiveness would bury a good decision.","task":"Write the 2-3 sentence answer: the reason, the evidence, and the invitation to make it official.","tips":["Give the reasoning like a colleague, not a suspect.","Evidence: what failed at the card setting, what the change fixed.","End by asking to update the card — that turns a deviation into an improvement."],"focus":["precision","audience"],"placeholder":"At the card setting we get seal failures every cold morning — bumping it 5 degrees clears them, and I log when I do it. If it holds up, can we get the card updated so it's official?"},
    {"id":"pressure-mfg-early-16","level":"early","profession":"industrial","title":"The question asked twice","scenario":"You answered 'will it ship today?' with a clear yes. Two minutes later they ask again, slower — they didn't believe you. Repeating the same word louder doesn't help; the same answer with the evidence underneath it does.","task":"Write the second answer: same verdict, now with the proof attached.","tips":["Keep the verdict identical — wobbling now costs you both answers.","Add the checkable evidence: counts, staging, what's left.","No irritation; being doubted is part of the job at first."],"focus":["impact","precision"],"placeholder":"Still yes — the first nine pallets are staged in lane 2 now, the last three come off the line by 3:00, and the truck isn't due until 5:00."},
    {"id":"pressure-mfg-early-17","level":"early","profession":"industrial","title":"The hypothetical you can't answer","scenario":"After the seal failure, your supervisor asks: 'Could this have affected the whole batch?' You genuinely don't know — you know when the failure was caught and what's held. The strong answer draws the line between known and unknown instead of guessing either way.","task":"Write a 2-3 sentence answer that states what you know, what you can't know, and whose call the rest is.","tips":["'What I know is...' then only knowns.","Name the unknown as an unknown, plainly.","Point at the test that resolves it — a QC pull, a sample check."],"focus":["precision","clarity"],"placeholder":"What I know: the failure was caught at 1:40 and everything after is on hold. Whether anything before 1:40 is affected, I can't say from the line — that's the QC sample pull to run."},
    {"id":"pressure-mfg-early-18","level":"early","profession":"industrial","title":"Asked about a co-worker's mistake","scenario":"Your supervisor asks what happened when your shift mate crashed the palletizer gate. You saw part of it. The pressure is to fill gaps — with theories, with charity, or with blame. The only safe ground is exactly what you observed.","task":"Write a 2-3 sentence answer limited to what you directly saw and heard.","tips":["Observed facts only: what you saw, from where, when.","Mark the edges: 'I didn't see what happened before that.'","Resist both theories and verdicts — neither is your data."],"focus":["precision","audience"],"placeholder":"I saw the gate come down while the pallet was still moving — I was at my station, about ten meters away. I didn't see the control panel, so I don't know what was pressed."},
    {"id":"pressure-mfg-early-19","level":"early","profession":"industrial","title":"'Is it safe to run?'","scenario":"The guard interlock on the press is acting up — sometimes it doesn't stop the ram when the door opens. Your supervisor, feeling the schedule, asks: 'Is it safe to run?' This is the question where a mumbled maybe fails everyone. You have a basis for a direct call.","task":"Write the 1-2 sentence answer: the direct call, and the basis for it.","tips":["Answer the question with the word it needs: yes or no.","One sentence of basis: what the interlock is failing to do.","On safety, being clear beats being agreeable — every time."],"focus":["clarity","impact"],"placeholder":"No — the interlock isn't stopping the ram when the door opens, and until it does that every time, this machine doesn't run."},
    {"id":"pressure-mfg-early-20","level":"early","profession":"industrial","title":"The number you only roughly know","scenario":"The plant manager, mid-tour, asks your line's scrap rate this week. You know it's around 3% but not the exact figure. Freezing looks bad; inventing decimals is worse. The answer is the rough number, labeled rough, with the exact one to follow.","task":"Write the 1-2 sentence answer giving the approximate figure honestly labeled.","tips":["Give the number with its label: 'roughly 3%.'","Offer the precise version and a time: 'exact figure in five minutes.'","An honest approximation beats a confident invention."],"focus":["precision","concision"],"placeholder":"Roughly 3% this week — I can pull the exact figure from the log in five minutes if you'd like it."},
    {"id":"pressure-mfg-early-21","level":"early","profession":"industrial","title":"The audit question with teeth","scenario":"The auditor asks: 'Do you ever skip the startup checklist when the schedule is tight?' The true answer is almost never — once, during the March rush, with the line lead's OK. Lying in an audit is the one unforgivable move; the precise truth is survivable.","task":"Write the honest 2-sentence answer, precise about the exception and its authorization.","tips":["Answer truthfully, including the once.","Precision protects you: when, why, who approved it.","Auditors trust people who volunteer their exceptions."],"focus":["clarity","precision"],"placeholder":"Once, during the March rush, with the line lead's sign-off — otherwise it's run every startup. It's the sign-off that made that OK, and it's on the record for that day."},
    {"id":"pressure-mfg-early-22","level":"early","profession":"industrial","title":"Caught between two seniors","scenario":"The mechanic says the jam was a material problem; the line lead says it was a setup problem. Both turn to you: 'You were there — which was it?' Picking a side buys an enemy. What you actually have is observations, and observations are neutral ground.","task":"Write the 1-2 sentence answer that reports what you observed without ruling for either.","tips":["Report the observable: what you saw, in sequence.","If your facts support one side, let the facts do it — don't editorialize.","'That's everything I saw' is a legitimate place to stop."],"focus":["precision","impact"]},
    {"id":"pressure-mfg-early-23","level":"early","profession":"industrial","title":"'Why didn't you flag this yesterday?'","scenario":"The bearing that failed today was already noisy yesterday — and you noticed, and didn't call it in. Now your supervisor asks the question you were dreading. A paragraph of excuses makes it worse. One sentence of ownership, then all forward motion.","task":"Write the 2-3 sentence answer: the plain ownership, then the containment and the change.","tips":["Own it in one sentence, no cushioning.","Don't over-confess either — one sentence, then move.","Spend the rest on now: what's contained, what you'll do differently."],"focus":["clarity","impact"],"placeholder":"I heard it yesterday and should have called it in — that's on me. Right now the spare is on its way and we're down about two hours; from here, anything I hear gets logged same shift, every time."},
    {"id":"pressure-mfg-early-24","level":"early","profession":"industrial","title":"The visitor's question that isn't yours","scenario":"A customer on a tour asks you directly: 'So could you fit our order in next month?' Scheduling promises aren't yours to make — but 'I can't tell you that' sounds cold, and guessing could commit the plant to something false. Deflect warmly, to the right person.","task":"Write the 1-2 sentence answer that declines the commitment gracefully and routes them right.","tips":["Warm first clause, clean boundary second.","Route them to the owner of the answer by name or role.","Don't leak a half-answer — 'probably' is a promise in a customer's ears."],"focus":["audience","clarity"],"placeholder":"That one's above my station — scheduling commitments come from our planning team, and Maria there can give you a real answer instead of my guess."},
    {"id":"pressure-mfg-early-25","level":"early","profession":"industrial","title":"'It's fine to run, right?'","scenario":"The line lead wants to restart with the jam sensor bypassed 'just until break.' They phrase it as a question that expects a yes: 'It's fine to run, right?' Everything social pulls toward agreement. The answer is no, and it needs to be a no that holds.","task":"Write the 1-2 sentence refusal: the no, the reason, and what would turn it into a yes.","tips":["Say no in the first three words.","One concrete reason — what the bypass removes.","Give the path to yes: sign-off, fix, or the sensor back in."],"focus":["impact","clarity"],"placeholder":"No — with the jam sensor bypassed nothing stops a wreck at full speed. Get maintenance to sign off or put the sensor back in, and I'll have us running in five minutes."}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-mfg-early-01","level":"early","profession":"industrial","title":"Before and after: the label staging","scenario":"You want your supervisor to make pre-staging the next order's labels standard practice. Listing the benefit flatly — 'it would save time' — won't move them. The persuasion is in the contrast: what changeovers look like now versus with the change.","task":"Write a 3-4 sentence pitch framed as before versus after.","tips":["Paint the 'now': the scramble, the minutes lost per changeover.","Paint the 'after': labels waiting, changeover ten minutes shorter.","Let the contrast carry it — then the small ask that gets there."],"focus":["impact","structure"],"placeholder":"Right now every changeover starts with someone jogging to the label room while the line sits — 10 to 15 minutes, three times a shift. Pre-stage the next order's labels during the run and the line restarts the moment the last case clears."},
    {"id":"narrative-mfg-early-02","level":"early","profession":"industrial","title":"Making the die wear concrete","scenario":"You're warning that the trim die is wearing out. 'It could become a problem' is abstract and will be deferred. The concrete version — parts failing inspection, an unplanned stop mid-order, a rework pile — is what gets a die change scheduled.","task":"Rewrite the warning so the consequence is vivid and specific.","tips":["Turn 'a problem' into the physical picture: failed parts, a dead line, rework hours.","Put a when on it: 'at this rate, next week.'","Concrete stakes get scheduled; vague ones get noted."],"focus":["impact","precision"],"placeholder":"At this wear rate, sometime next week parts start failing edge inspection mid-order — that's an unplanned stop, a die change under pressure, and a rework pile, versus a planned 40-minute swap on Thursday."},
    {"id":"narrative-mfg-early-03","level":"early","profession":"industrial","title":"Pre-empting 'too expensive'","scenario":"You're proposing a second calibrated torque wrench for the line so checks don't queue behind one tool. Your supervisor's first thought will be the cost. If you name the objection and answer it before they raise it, the proposal lands twice as clean.","task":"Write a 3-sentence proposal that raises and answers the cost objection yourself.","tips":["State the proposal and its benefit first.","Name the objection out loud: 'it's a few hundred dollars.'","Answer with the payback: minutes recovered, checks not skipped."],"focus":["impact","structure"],"placeholder":"I'd like a second torque wrench for the line — right now checks queue behind one tool and get rushed. It's a few hundred dollars, but we lose more than that in one skipped check that lets a bad batch through."},
    {"id":"narrative-mfg-early-04","level":"early","profession":"industrial","title":"'We've always done it this way'","scenario":"You want the crew to adopt a written changeover checklist. You already know the pushback: 'we've always done it from memory and it's been fine.' Arguing that they're wrong loses the room. Acknowledging what works and showing what memory misses is the route in.","task":"Write a 3-4 sentence pitch that grants the old way its due and then shows the gap.","tips":["Start by crediting what's true — experienced hands rarely miss.","Then the gap: the misses cluster on rushed days and unusual products.","Frame the checklist as protecting the crew's record, not doubting it."],"focus":["audience","impact"],"placeholder":"From memory works most days — this crew rarely misses. But the two setup misses this quarter both happened on rushed changeovers to odd products, exactly where memory gets thin. A one-page checklist costs 90 seconds and protects the record we're proud of."},
    {"id":"narrative-mfg-early-05","level":"early","profession":"industrial","title":"The mirror at the blind corner","scenario":"You want a convex mirror at the blind corner where the forklift nearly hit you. The request form asks for justification. 'It's dangerous' is true and weak. The moment itself — told concretely, with the traffic count — is what justifies a purchase.","task":"Write a 3-4 sentence justification that makes the near-miss vivid and the fix cheap by comparison.","tips":["Tell the moment: forks a meter away, alarm lost under the grinder noise.","Add the exposure: how many crossings a shift.","Price the mirror against one incident — the math argues for you."],"focus":["impact","precision"],"placeholder":"On Tuesday a forklift came around the line 5 corner and its forks stopped a meter from me — the backup alarm was lost under the grinder noise. That corner gets crossed on foot maybe forty times a shift, blind in both directions. A convex mirror costs less than the paperwork on one injury."},
    {"id":"narrative-mfg-early-06","level":"early","profession":"industrial","title":"Four weeks, one photo-eye","scenario":"The same infeed photo-eye has failed four Mondays running and each time it's treated as a one-off. You're raising it at the maintenance planning meeting. Four isolated tickets tell no story; one pattern, told as a pattern, demands a root cause.","task":"Write a 3-4 sentence case that assembles the incidents into one story with an arc.","tips":["Open with the pattern, not the latest incident: 'four Mondays in a row.'","Give the cumulative cost — total minutes down across the four.","End at the turn: stop replacing the eye, find what's killing it."],"focus":["structure","impact"],"placeholder":"The line 3 infeed photo-eye has failed four Mondays in a row — that's not four bad sensors, that's one cause we haven't found. Together those failures cost 190 minutes of production. I'd like the next fix to be a root-cause look, not a fifth replacement."},
    {"id":"narrative-mfg-early-07","level":"early","profession":"industrial","title":"Selling the lockout tags at toolbox talk","scenario":"The new lockout tags are being ignored — the crew sees them as paperwork. You've got two minutes at the toolbox talk. Reciting the policy will bounce off. What lands is the story of the reach into the 'stopped' machine that restarts.","task":"Write the 2-3 sentences you'd say to make the tag feel like protection, not paperwork.","tips":["Open with the scene everyone can picture: hands in a machine that someone else restarts.","The tag is the plot twist — the restart that can't happen.","Talk like a crewmate, not a poster."],"focus":["audience","impact"]},
    {"id":"narrative-mfg-early-08","level":"early","profession":"industrial","title":"Making 200 units a day human","scenario":"Your line scraps about 200 units a day and the number has gone invisible — it's wallpaper. You want the crew to feel it again at the huddle. Raw numbers don't land; translations do: hours of the crew's own work, a full pallet, a day's pay in material.","task":"Write the 2-3 sentence translation you'd say at the huddle to make the scrap number felt.","tips":["Convert to something with weight: 'a full pallet of our work, every day, in the dumpster.'","Keep one real number so it's not just rhetoric.","End with the one behavior that moves it most."],"focus":["impact","audience"],"placeholder":"Two hundred units a day is a full pallet of our own work going in the dumpster every single day — an hour of this crew's shift, gone. Most of it traces to the first thirty minutes after changeover, so that's where I'm asking us to slow down."},
    {"id":"narrative-mfg-early-09","level":"early","profession":"industrial","title":"Persuading the planner to resequence","scenario":"Tomorrow's schedule runs the orders in a sequence that forces two extra changeovers. Reordering them — dark colors after light, same bottle sizes back to back — saves nearly an hour. The planner doesn't feel changeovers; they feel truck deadlines. Argue in their currency.","task":"Write a 2-3 sentence message that sells the resequence in the planner's terms.","tips":["Lead with what they get: an hour of capacity, same truck commitments met.","Show you checked their constraint: no ship date moves.","Make the swap concrete: 'run 7734 before 7738.'"],"focus":["audience","impact"],"placeholder":"If we run 7734 before 7738 tomorrow, we drop two changeovers and gain almost an hour of run time — and I checked, no ship date moves. Same trucks, more buffer."},
    {"id":"narrative-mfg-early-10","level":"early","profession":"industrial","title":"The case for stopping the line","scenario":"You suspect the filler is drifting and want a 20-minute stop to verify. Your supervisor hears 'stop' as lost production. The persuasion is the comparison: 20 known minutes now versus the possible afternoon of rework and a quality hold if the drift is real.","task":"Write a 2-3 sentence case that weighs the small certain cost against the large possible one.","tips":["Name both costs with numbers: 20 minutes versus a 4-hour rework.","Give the probability honestly — 'I'd say even odds it's drifting.'","Make the recommendation yours: 'I think we stop.'"],"focus":["impact","precision"],"placeholder":"I want a 20-minute stop to verify the filler — I'd say even odds it's drifting. If it is and we keep running, that's an afternoon of rework and a hold on everything since noon. Twenty minutes now is the cheap version of this."},
    {"id":"narrative-mfg-early-11","level":"early","profession":"industrial","title":"The suggestion with a story arc","scenario":"You're writing up the tool shadow board idea for the improvement program. A flat feature list — 'board, outlines, labels' — reads like a catalog. The winning entries tell a small story: the problem lived, the cost counted, the fix, the payoff.","task":"Write the 4-sentence entry as an arc: problem, cost, fix, payoff.","tips":["Open in the problem: the changeover stalled while someone hunts the 13 mm wrench.","One sentence of counted cost — minutes per changeover, changeovers per week.","Fix and payoff each get a sentence; keep the payoff in hours or units."],"focus":["structure","impact"],"placeholder":"Twice this week a changeover stalled while we hunted for the torque driver someone had borrowed. Tool hunting costs us 10-15 minutes per changeover, fifteen changeovers a week."},
    {"id":"narrative-mfg-early-12","level":"early","profession":"industrial","title":"Pre-empting 'it'll slow the line'","scenario":"You want to add a quick visual check at the case packer after two crushed-corner escapes. The objection is predictable: 'another check will slow the line.' You've timed it — three seconds, inside the machine's own cycle. Say so before they do.","task":"Write a 3-sentence proposal that names the speed objection and kills it with your timing data.","tips":["Propose, then voice their objection in their words.","Answer with the measurement: three seconds, inside the cycle, zero rate loss.","Close with what the check prevents — the escapes you already had."],"focus":["structure","precision"],"placeholder":"I want to add a corner check at the case packer — and before anyone says it slows the line: I timed it, three seconds, fully inside the machine cycle. Zero rate cost, and it catches exactly the crushed corners that reached the customer twice last month."},
    {"id":"narrative-mfg-early-13","level":"early","profession":"industrial","title":"Getting your work order prioritized","scenario":"Maintenance has forty open work orders and yours — a bearing getting louder on the main drive — is sitting in the queue behind squeaky door hinges. The queue is first-come-first-served unless someone makes the risk legible. That someone is you.","task":"Write a 2-3 sentence note to the maintenance lead that moves your order up by making the risk concrete.","tips":["Name what happens if it fails: main drive, whole line down, days for the part.","Give the trend: louder each shift — this is a countdown, not a state.","Ask for the specific slot, not just 'soon.'"],"focus":["impact","audience"],"placeholder":"The main drive bearing on line 4 is louder every shift — when it goes, the whole line is down and that part is a three-day lead time. Can we get it on this week's PM slot before it chooses its own timing?"},
    {"id":"narrative-mfg-early-14","level":"early","profession":"industrial","title":"The cross-training pitch","scenario":"You want to be trained on the palletizer. Framed as 'I want to grow,' it's a favor to you and easy to defer. Framed as line resilience — one operator out sick means the whole back end stops — it's a favor to the operation. Same ask, different story.","task":"Write a 2-3 sentence pitch framed around what the line gains, with your growth as the footnote.","tips":["Lead with the line's exposure: one person deep at the palletizer.","Your ask is the fix for THAT problem.","Suggest the low-cost path: shadowing during slow runs."],"focus":["audience","impact"],"placeholder":"We're one person deep on the palletizer — when Sam's out, the back end stops. Train me as backup and that single point of failure goes away; I could shadow during the slow Thursday runs without costing any coverage."},
    {"id":"narrative-mfg-early-15","level":"early","profession":"industrial","title":"The mat that pays for itself","scenario":"You want anti-fatigue mats at the inspection stations. 'Our feet hurt' is real but easy to file under comfort. The stronger story is the one you noticed in the data: visual checks miss more in the last two hours of shift, when everyone's aching and shifting weight.","task":"Write a 3-sentence case that ties the mats to late-shift inspection quality, not comfort.","tips":["Lead with the quality pattern: late-shift misses.","Connect it: tired feet cut inspection attention — that's the mechanism.","The mats become a quality fix that also happens to be humane."],"focus":["impact","structure"],"placeholder":"Most of our visual-check escapes cluster in the last two hours of shift — the hours everyone's shifting foot to foot on concrete. Anti-fatigue mats at the inspection stations attack that directly. Comfort is the side effect; the target is late-shift catch rate."},
    {"id":"narrative-mfg-early-16","level":"early","profession":"industrial","title":"Before and after: the second bin","scenario":"You want a second fastener bin at your assembly station so a refill doesn't mean stopping. It's a tiny ask that keeps getting forgotten because it's never been made vivid. One walk-through of a refill — everything that stops — would fix that.","task":"Write a 2-3 sentence before/after pitch for the second bin.","tips":["Before: bin runs dry, station stops, you walk, the line gaps.","After: swap bins in five seconds, refill happens while you work.","Small fixes deserve small pitches — but with the contrast intact."],"focus":["concision","impact"],"placeholder":"Every time my fastener bin runs dry the station stops while I walk for a refill — four times a shift, five minutes each. With a second bin I swap in five seconds and refill the empty one while the line runs."},
    {"id":"narrative-mfg-early-17","level":"early","profession":"industrial","title":"Talking a mate out of the bypass","scenario":"A shift mate keeps clearing jams with the guard bypassed — faster, and they've never been hurt. Preaching bounces off; the stats feel abstract. What works is making the one bad outcome concrete and theirs, without making them defensive.","task":"Write the 2-3 sentences you'd say, peer to peer, making the stake concrete without lecturing.","tips":["Start alongside, not above: you get why — it IS faster.","Make the outcome specific and personal, not statistical.","Give them an out that saves face: a faster safe method, or help fixing the slow guard."],"focus":["audience","impact"]},
    {"id":"narrative-mfg-early-18","level":"early","profession":"industrial","title":"The 'so what' of the drift","scenario":"You're reporting that fill weights have drifted up 2 grams over three weeks — still in spec. Read flat, it's a shrug: still in spec, who cares. The story is where the line points: out of spec in about two more weeks, mid-quarter, unless the drift gets addressed.","task":"Write a 2-3 sentence report that carries the trend to its 'so what.'","tips":["The number matters because of where it's HEADED — say the destination.","Give the arrival date at spec limit at current rate.","End with the cheap intervention now versus the expensive one later."],"focus":["precision","impact"],"placeholder":"Fill weights have drifted up 2 grams in three weeks — still in spec, but at this rate we cross the limit in about two more. A filler calibration now costs 30 minutes; catching it after a QC hold costs days."},
    {"id":"narrative-mfg-early-19","level":"early","profession":"industrial","title":"Planned versus unplanned, priced","scenario":"You're making the case to schedule the gearbox replacement now, while it still runs. The persuasion is arithmetic nobody has done out loud: a planned 4-hour swap on a Sunday versus an unplanned failure mid-order — line down for days waiting on parts, order shorted, overtime.","task":"Write a 3-sentence case built on the planned-versus-unplanned comparison.","tips":["Price both futures in the same units: hours down, orders at risk.","The gearbox WILL be replaced either way — only the timing is a choice.","Recommend the slot: 'Sunday's maintenance window.'"],"focus":["impact","precision"],"placeholder":"That gearbox gets replaced either way — the only choice is whether it's a planned 4-hour swap on Sunday or a mid-order failure with a three-day parts wait and a shorted customer. Same part, very different bill. I recommend Sunday's window."},
    {"id":"narrative-mfg-early-20","level":"early","profession":"industrial","title":"Winning night shift back to the sheet","scenario":"Night shift has stopped filling in the downtime tracking sheet — 'nobody reads it anyway.' Except somebody did: the sheet's data is what got the new labeler approved. They don't know that story, and it's the only argument that will work.","task":"Write a 2-3 sentence note to the night crew that connects their data to the win it bought.","tips":["Lead with the payoff they didn't see: the sheet bought the labeler.","Data they enter is ammunition for fixes on THEIR shift.","Skip the compliance framing entirely — this is self-interest."],"focus":["audience","impact"],"placeholder":"That downtime sheet everyone hates? Three months of it is what got the new labeler approved — the numbers made the case nobody's word could. Every line you log is ammunition for the next fix, and night shift's problems only get fixed if they're on paper."},
    {"id":"narrative-mfg-early-21","level":"early","profession":"industrial","title":"Patch now or fix right","scenario":"The reject gate can be patched in 30 minutes or properly rebuilt in 3 hours. You've been asked which, and you have a view: the patch has already failed twice. Presenting both options neutrally wastes what you know. Compare them honestly, then recommend.","task":"Write a 3-4 sentence comparison that ends in your recommendation.","tips":["Give each option its true cost and lifespan — including the patch's record.","Compare in the same units so the choice is visible.","Then choose: 'I recommend the rebuild, and here's the least painful slot.'"],"focus":["structure","impact"],"placeholder":"The patch is 30 minutes but the last two patches each failed within a week — we've effectively paid for the rebuild already, in installments. The rebuild is 3 hours, once. I recommend the rebuild during tomorrow's changeover, when we're down anyway."},
    {"id":"narrative-mfg-early-22","level":"early","profession":"industrial","title":"Five minutes of 5S","scenario":"You want the crew to spend the last five minutes of each shift resetting the station — tools home, floor clear, notes done. Said as a rule, it's more work. Said as a story — what walking into a reset station at 6 a.m. feels like versus the alternative — it's a gift shifts give each other.","task":"Write the 2-3 sentences you'd say at the huddle to sell the five-minute reset.","tips":["Paint the receiving end: starting your shift at a station that's ready.","Make it reciprocal — you get what the last shift leaves you.","Keep the ask tiny and bounded: five minutes, same five things."],"focus":["audience","impact"]},
    {"id":"narrative-mfg-early-23","level":"early","profession":"industrial","title":"The buddy-system pitch after the scrap","scenario":"A new hire ran 300 bad parts on their second solo day — the training checklist said they were ready, but nobody was nearby when the feeder drifted. You think new hires need a named buddy for week one. The scrap incident is your exhibit A; use it without blaming the hire.","task":"Write a 3-4 sentence pitch for the buddy system built on the incident, aimed at your supervisor.","tips":["Tell the incident as a system gap, not a person's failure.","The buddy is the cheap patch for exactly that gap.","Cost it honestly: a named person, week one, no extra headcount."],"focus":["structure","audience"],"placeholder":"Tuesday's 300 scrapped parts weren't the new hire's failure — the feeder drifted and there was nobody within shouting distance who'd seen that before. A named week-one buddy on the same line closes that gap for free."},
    {"id":"narrative-mfg-early-24","level":"early","profession":"industrial","title":"Persuading QC to sample earlier","scenario":"QC pulls their first sample two hours into each run. Twice this month a setup issue ran undetected for those two hours — thousands of units to re-check. You want a first pull at 15 minutes. To QC, that's extra work; the story that wins is what it saves them.","task":"Write a 2-3 sentence case to the QC lead, argued from their workload, not yours.","tips":["Their currency: samples pulled versus units re-checked after an escape.","One 15-minute pull versus re-checking a two-hour run — do that math out loud.","Use this month's two incidents as the evidence."],"focus":["audience","precision"],"placeholder":"Both of this month's setup escapes ran two hours before the first sample caught them — that was 4,000 units re-checked each time. One extra pull at the 15-minute mark costs you five minutes and would have caught both at a few hundred units."},
    {"id":"narrative-mfg-early-25","level":"early","profession":"industrial","title":"The forty-minute wait, retold","scenario":"Last month the line sat 40 minutes waiting for a drive belt from the central crib. You want a small spare-parts kit kept at the line, and the crib pushback is 'inventory control.' Your best asset is that 40-minute story, told so the listener sits in it.","task":"Write a 3-4 sentence case for the line-side kit, anchored in the 40-minute wait and answering the inventory objection.","tips":["Open inside the wait: line dead, crew standing, belt a five-minute fix.","Scope the kit tightly — five named parts, signed out, counted monthly.","Answering the objection with the kit's rules beats arguing inventory doesn't matter."],"focus":["structure","impact"],"placeholder":"Last month line 4 stood dead for 40 minutes waiting on a drive belt — a five-minute fix once it arrived. I'm asking for a five-part kit at the line: belt, fuses, photo-eye, two rollers, signed out and counted monthly, so inventory control still holds."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-mfg-early-01","level":"early","profession":"industrial","title":"The Tuesday that became Friday","scenario":"You told your supervisor the rework on the mislabeled cases would finish Tuesday. It won't — a second bad batch surfaced and it's now Friday. Your draft opens with three sentences about the discovery before the new date appears. Clear is kind: date first.","task":"Write a 3-sentence message: the slip up front, the reason in one sentence, the recovery plan.","tips":["New date in the first sentence — don't make them dig.","One sentence of reason; it's an explanation, not a defense.","End with what you're doing to protect Friday."],"focus":["clarity","impact"],"placeholder":"The rework will finish Friday, not Tuesday — a second mislabeled batch surfaced when we opened the back pallets. I've pulled everything suspect into one lane so there are no more surprises, and Friday holds."},
    {"id":"hard-mfg-early-02","level":"early","profession":"industrial","title":"The scrap that's yours","scenario":"You ran an hour at the wrong temperature setting — your mistake, caught at the quality check. About 400 units are scrap. Your supervisor will hear about it either way; the version they should hear first is yours, plainly owned, with the numbers.","task":"Write a 2-3 sentence report that owns the error, scopes the damage, and states the prevention.","tips":["'I set it wrong' — active voice, first sentence.","Scope with numbers: how many units, what window.","One concrete prevention step, not a promise to 'be careful.'"],"focus":["clarity","impact"],"placeholder":"I set the zone 2 temperature 15 degrees low after the changeover — about 400 units from 9:00-10:00 are scrap. From now on I'm verifying setpoints against the card before restart, every time."},
    {"id":"hard-mfg-early-03","level":"early","profession":"industrial","title":"The target you'll miss — said at noon","scenario":"By noon you can see the shift will land around 3,600 units against a 4,400 target — the morning breakdown ate too much. Telling your supervisor now, while they can still adjust trucks and staffing, is worth far more than a surprised apology at 6:00.","task":"Write a 2-3 sentence heads-up: the projected miss, the cause in a clause, what could still change it.","tips":["Lead with the projection and the gap.","Early bad news is a gift; deliver it like one — no burying.","Offer the levers that still exist: overtime, a second changeover crew."],"focus":["impact","precision"],"placeholder":"Heads-up at the half: we're tracking to about 3,600 against the 4,400 target — the morning breakdown cost us two hours. If we can get a second pair of hands at the 2:00 changeover, I can claw back maybe 300 of it."},
    {"id":"hard-mfg-early-04","level":"early","profession":"industrial","title":"The Saturday you can't cover","scenario":"A crewmate asks you to take their Saturday shift. You can't — it's your kid's tournament. Your draft reply is a maze of 'let me see' and 'maybe if.' False hope costs them the days they need to find someone else. A clean no, now, is the kind version.","task":"Write a 2-sentence decline: the plain no, the real reason, and any actual help you can offer.","tips":["'I can't' in the first three words.","One honest reason — you don't owe a defense.","Offer only what's real: another name, a different weekend."],"focus":["clarity","concision"],"placeholder":"I can't take Saturday — it's my kid's tournament and I'll be out of town. Reyes was looking for extra hours last week; want me to ask him?"},
    {"id":"hard-mfg-early-05","level":"early","profession":"industrial","title":"The trainee's failing parts","scenario":"The new hire you're mentoring is doing the crimp step wrong — a third of their parts are failing your check. They're trying hard and you like them, which is exactly why your feedback keeps coming out too soft to use. They need the specific fix, not comfort.","task":"Write the 2-3 sentences you'd say: the specific problem, the impact, and the concrete correction.","tips":["Name the exact step and the exact error — not 'some issues.'","Impact in numbers: a third failing the check.","Give the physical correction: what their hands should do differently."],"focus":["clarity","precision"],"placeholder":"Your crimps are seating at an angle — about a third are failing my pull test. The fix is square contact before you squeeze: set the jaw flush, then crimp. Run ten with me watching and we'll lock it in."},
    {"id":"hard-mfg-early-06","level":"early","profession":"industrial","title":"The reach you have to call out","scenario":"You watched a crewmate reach past the light curtain to clear a part while the machine cycled — the second time this week. Saying nothing makes you the last person who could have spoken before the bad day. It has to be said, directly, without making them the villain.","task":"Write the 2-3 sentences you'd say to them, direct about the act, straight about why.","tips":["Name the specific act and when — no vague 'being unsafe.'","Say the stake plainly: that machine doesn't know your hand from a part.","Direct and personal beats reporting them cold — but say you WILL escalate if it continues."],"focus":["clarity","impact"]},
    {"id":"hard-mfg-early-07","level":"early","profession":"industrial","title":"The fix that didn't hold","scenario":"Maintenance closed the work order on the case sealer this morning; by 1:00 the same fault was back. The mechanic is proud of the quick turnaround. Your message needs to reopen the job without turning it into a verdict on their work.","task":"Write a 2-sentence message: the fault is back, the facts of when, and the ask — no blame, no softening the fact.","tips":["State the observable: same symptom, returned at 1:00, four hours after the fix.","Skip both the accusation AND the apology — it's just a fact that needs action.","Ask for the next step: another look, a different part, an escalation."],"focus":["precision","clarity"],"placeholder":"The sealer fault is back — same left-flap symptom, started again at 1:00, about four hours after the morning fix. Can you take another look? Whatever it is, it survived the first repair."},
    {"id":"hard-mfg-early-08","level":"early","profession":"industrial","title":"The tool you broke","scenario":"You dropped the calibrated torque driver and now it reads wrong. Nobody saw. The next person to use it will trust a lying tool on real product — unless you report it now. The message costs you a wince; silence costs a batch.","task":"Write the 2-sentence report: what happened, the state of the tool, and what you've done with it.","tips":["Plain ownership: 'I dropped it' — not 'it fell.'","The critical fact: it reads wrong now — say what you observed.","Say where the tool is: tagged and pulled from service, not back on the shelf."],"focus":["clarity","precision"],"placeholder":"I dropped the torque driver and it's reading about 2 Nm high against the check weight — I've tagged it out of service and left it with the crib for recalibration. Wanted you to know before anyone reaches for it."},
    {"id":"hard-mfg-early-09","level":"early","profession":"industrial","title":"The suspect pallet that already shipped","scenario":"Reviewing your notes, you realize the pallet that failed this morning's seal check is the one that shipped at noon — the hold tag went on the wrong pallet. This is the worst kind of news and it ages terribly. It needs to go up now, stated so recovery can start immediately.","task":"Write the 2-3 sentence escalation: what shipped, the identifying details, and the recovery ask.","tips":["First sentence: suspect product is on a truck — the headline.","Every identifier you have: order, pallet, truck, departure time.","Ask for the action: contact the carrier, hold at the customer dock."],"focus":["impact","precision"],"placeholder":"The pallet that failed this morning's seal check shipped at noon — the hold tag ended up on the wrong pallet. It's order 8823, pallet 12 of 12, on the 12:15 truck to the Kelowna DC. We need the carrier called now so it's held at their dock."},
    {"id":"hard-mfg-early-10","level":"early","profession":"industrial","title":"The overtime you're declining","scenario":"Your supervisor asks you to stay four extra hours tonight — third time this week. You're worn down, and tired hands around moving machinery is its own safety case. 'I guess, if you really need me' is a yes wearing a no's clothes. Decline it straight.","task":"Write the 1-2 sentence decline: plain, with the reason, holding the door open for next time.","tips":["A clear no now beats a resentful yes at hour eleven.","Fatigue near machinery is a legitimate reason — you can say it.","Offer what's true: 'I can do tomorrow' — only if you mean it."],"focus":["clarity","concision"],"placeholder":"I can't stay tonight — after two doubles this week I'm past the point where I trust myself around the press. I can take extra hours Thursday if that helps."},
    {"id":"hard-mfg-early-11","level":"early","profession":"industrial","title":"The procedure that isn't working","scenario":"The new startup procedure — written by your supervisor — has added twenty minutes and two new defect types since it rolled out. Telling the author their procedure is hurting the line is delicate, but three more weeks of polite silence costs real production.","task":"Write a 3-sentence message: the data, the specific step causing it, and a proposed tweak — aimed at the procedure, not the author.","tips":["Lead with observed numbers since rollout, not opinions.","Point at the step, not the person: 'step 4 has the purge before the heat-up.'","Propose the fix as a question: 'could we trial swapping them?'"],"focus":["precision","audience"],"placeholder":"Since the new startup rolled out we're averaging 20 minutes longer to first good part, and the cold-start smears are new. I think it's step 4 — purging before the heat-up instead of after. Could we trial the old order on one startup and compare?"},
    {"id":"hard-mfg-early-12","level":"early","profession":"industrial","title":"Correcting the twenty-year hand","scenario":"The most senior operator on the floor set up the run — and used last quarter's spec sheet. The parts will fail. Telling a twenty-year veteran they got it wrong needs care, but the parts don't care about seniority. The document is your ally: it's the revision that changed, not their skill.","task":"Write the 1-2 sentences you'd say, correcting the setup while giving them an easy path to fix it.","tips":["Blame the revision, honestly: 'the spec changed in April.'","Bring the evidence in hand — the new sheet, not your memory.","Let them make the change; you're delivering information, not a verdict."],"focus":["audience","clarity"],"placeholder":"Heads-up before this run gets going — the fill spec changed in April and this setup matches the old sheet. Here's the current revision; want a hand re-dialing it?"},
    {"id":"hard-mfg-early-13","level":"early","profession":"industrial","title":"The batch that's a write-off","scenario":"QC confirmed it: the whole morning batch — 2,100 units — fails and can't be reworked. Your supervisor is about to walk into their production meeting. They need the number, the cause, and the containment in the first breath, because they'll be repeating it upstairs in an hour.","task":"Write the 3-sentence message: the write-off up front, the confirmed cause, what's contained and running now.","tips":["The number leads: 2,100 units, non-reworkable.","Cause in one sentence — confirmed, not speculated.","Give them the 'and now' they'll be asked for: line status, containment."],"focus":["clarity","impact"],"placeholder":"QC confirmed the full morning batch — 2,100 units — fails and can't be reworked. Root cause is the contaminated resin lot, confirmed by the material test. The lot is quarantined, the line is running clean on the new lot since 11:00."},
    {"id":"hard-mfg-early-14","level":"early","profession":"industrial","title":"Telling shipping the truck goes light","scenario":"Shipping has a truck scheduled at 5:00 for the full order. The order won't be full — the afternoon's breakdown means 14 pallets, not 18. Shipping can rebook, part-ship, or hold, but only if they hear now. Your message has to be the version they can act on.","task":"Write a 2-sentence message with the shortfall, the ready count, and the ask for their call.","tips":["Their units: pallets and dock times, not machine troubles.","State what IS ready so part-shipping stays on the table.","Ask for their decision explicitly — it's their call to make."],"focus":["audience","concision"],"placeholder":"The 5:00 truck for order 7734 will have 14 pallets, not 18 — the last 4 land tomorrow by 10:00. Your call: part-ship tonight or rebook for a full load tomorrow?"},
    {"id":"hard-mfg-early-15","level":"early","profession":"industrial","title":"Worse after the repair","scenario":"The wrapper came back from its overhaul and it's running worse than before it left — jamming at speeds it used to handle. The mechanic spent their whole weekend on it. The message has to be honest about the state without spitting on the effort.","task":"Write a 2-3 sentence message: the specific regression, the comparison to before, the ask — respectful and unsoftened.","tips":["Facts of the regression: jams at 40 now, ran clean at 55 before.","Acknowledge the work without diluting the message.","The ask: another pass, with you there to show the symptom live."],"focus":["precision","audience"],"placeholder":"I know the weekend went into the wrapper, so this isn't the news either of us wants: it's jamming at 40 a minute, and before the overhaul it ran clean at 55. Can you come see it live this afternoon? Something in the rebuild changed the film path."},
    {"id":"hard-mfg-early-16","level":"early","profession":"industrial","title":"The check you skipped","scenario":"You missed the 2:00 quality check — got pulled into the jam and never went back. It's 4:30 and the sheet has a hole. Backfilling a fake reading is the career-ending option. Reporting it means two hours of product with no verification — that has to be QC's call.","task":"Write the 2-3 sentence report: the missed check, the exposure window, and the handoff of the disposition call.","tips":["State the miss plainly — no 'I got busy' padding.","Define the exposure: 12:00 to now, unverified.","Hand the disposition to QC; don't decide the product's fate yourself."],"focus":["clarity","precision"],"placeholder":"I missed the 2:00 check — got pulled into the jam and never got back to it. That leaves noon to now unverified, about 900 units. Flagging it to QC now for the call on sampling; the 4:00 check I just ran is in spec, for what it's worth."},
    {"id":"hard-mfg-early-17","level":"early","profession":"industrial","title":"The handoff notes you can't use","scenario":"Your counterpart on days leaves handoff notes that are three words or missing entirely, and twice this week you've been ambushed by an issue they knew about. You'll see them for ninety seconds at shift change. It needs to be raised — specific, unheated, fixable.","task":"Write the 2-3 sentences you'd say at the handoff window: the specific gap, the cost, the concrete ask.","tips":["Cite the incident, not the character: 'Tuesday's oven issue wasn't in the notes.'","Cost in real terms: an hour of my shift diagnosing what you already knew.","Ask for something small and specific: three lines — status, issues, watch-fors."],"focus":["clarity","audience"]},
    {"id":"hard-mfg-early-18","level":"early","profession":"industrial","title":"Radio silence on channel 2","scenario":"A crewmate uses the emergency radio channel for chat — scores, lunch plans. Funny until the day a real call gets stepped on. You're not their boss, but you're the one who's noticed. Peer-to-peer, it's one sentence of behavior, one of stakes, one of ask.","task":"Write the behavior-impact-ask you'd say, kept light enough to keep the peace and clear enough to stick.","tips":["The behavior, factually: chat on channel 2.","The stake: the one call that channel exists for, stepped on.","Keep your tone a teammate's — the content does the enforcing."],"focus":["concision","audience"]},
    {"id":"hard-mfg-early-19","level":"early","profession":"industrial","title":"The no that stops the restart","scenario":"The supervisor wants the line restarted now; the jam is cleared but the guard panel is still off, and the mechanic is ten minutes away. 'Just this once, I'll stand right here.' Your no has to survive rank, schedule pressure, and the word 'just.'","task":"Write the 1-2 sentence refusal that holds: the no, the line it protects, and the ten-minute path to yes.","tips":["Say no to the restart, not to the person.","Anchor to the rule that outranks you both: no run with guards off.","Make the yes cheap: ten minutes, panel on, full speed."],"focus":["impact","clarity"],"placeholder":"Not with the panel off — that's the one rule that outranks the schedule, mine and yours both. Mechanic's ten minutes out; panel goes on, and I'll have us at full speed before the half hour."},
    {"id":"hard-mfg-early-20","level":"early","profession":"industrial","title":"'I'm not ready to run solo'","scenario":"Your trainer wants to sign you off on the molder tomorrow — you've hit the checklist items once each. You know the difference between done-once and reliable, and you're not there on the fault recovery steps. Saying so feels like failing; it's actually the most trustworthy thing you can say.","task":"Write the 2-sentence message: not ready, the specific gaps, and the bounded ask for what would close them.","tips":["Name the specific gaps, not general nerves — 'fault recovery, cold starts.'","Bound the ask: two more supervised shifts, not 'more time.'","Knowing your edge is a skill; deliver it like one."],"focus":["clarity","precision"],"placeholder":"I'm not ready for solo sign-off yet — I've done the fault recovery and cold-start procedures once each, and once isn't reliable. Two more supervised shifts hitting those specifically and I'll be solid."},
    {"id":"hard-mfg-early-21","level":"early","profession":"industrial","title":"Their pallets, your problem","scenario":"The upstream line's pallets keep arriving with the bottom layer crushed — third day running, and your crew loses time re-stacking before you can feed your machine. The operators there are your peers. It needs raising with them directly before it becomes a supervisor matter.","task":"Write the 2-3 sentence message to the upstream crew: the pattern, the cost on your end, the ask — colleague to colleague.","tips":["Pattern with numbers: three days, roughly two pallets a day.","Your cost, concretely: 20 minutes re-stacking per pallet.","Ask about THEIR end too — something may have changed on their stacker."],"focus":["audience","clarity"],"placeholder":"Three days running we're getting pallets with the bottom layer crushed — about two a day, and each one costs us 20 minutes re-stacking before we can feed. Did something change on your stacker settings? Happy to come look at it together."},
    {"id":"hard-mfg-early-22","level":"early","profession":"industrial","title":"Short before the promise","scenario":"You've heard your supervisor is about to confirm full delivery of order 5561 to the customer on today's call. From the floor math, the order will short about 500 units. Contradicting the number they're about to promise is uncomfortable — and exactly why it can't wait.","task":"Write the 2-sentence message that gets to them before the call: the short, the basis, the timing flag.","tips":["Open with why now: 'before your customer call.'","The number and your basis for it in one sentence.","You're not overriding them — you're arming them."],"focus":["impact","concision"],"placeholder":"Before your customer call: 5561 is tracking about 500 units short — we lost the margin in yesterday's downtime and today's rate won't close it. Wanted the real number in your hand before it's promised."},
    {"id":"hard-mfg-early-23","level":"early","profession":"industrial","title":"The mislabel that's already gone","scenario":"You discover that yesterday you put the 12-pack labels on a run of 6-packs — and it shipped last night. Nobody has noticed yet. The gap between now and when you report it is the only part of this that's truly yours to control, and it should be minutes, not days.","task":"Write the 2-3 sentence report: the error owned, the scope with identifiers, and the first recovery step.","tips":["Own it in the first clause — 'I mislabeled.'","Scope: which order, how many cases, which truck.","Reporting fast is the redemption arc; write like you know it."],"focus":["clarity","impact"],"placeholder":"I mislabeled yesterday's 2:00 run — 12-pack labels on 6-pack cases, about 80 cases on order 5590, shipped on last night's truck. Flagging it now so we can call the DC before they hit their shelves; I've got the lot numbers ready."},
    {"id":"hard-mfg-early-24","level":"early","profession":"industrial","title":"The machine they championed","scenario":"Your supervisor pushed hard to buy the new automatic taper, and it's underperforming — more misfeeds than the manual station it replaced. Everyone on the crew knows; nobody wants to tell the person who championed it. Data, not opinions, is the kind way in.","task":"Write a 3-sentence message: the numbers versus the old station, one observed cause, and a constructive next step.","tips":["Numbers only — 'eleven misfeeds a shift versus two' needs no adjectives.","Offer an observed cause: it struggles with the recycled-content cases.","Frame the next step as making their purchase succeed, not proving it failed."],"focus":["precision","audience"],"placeholder":"Three weeks of tracking on the new taper: eleven misfeeds a shift versus two on the old station. It's mostly the recycled-content cases — the flaps don't sit flat and the feeder can't grip them. Worth getting the vendor in? With a fix for those cases this thing hits its numbers."},
    {"id":"hard-mfg-early-25","level":"early","profession":"industrial","title":"Your friend's scrap on your count","scenario":"Your friend on the adjacent station has been quietly moving their reject parts into your bin — small numbers, but your scrap count is wearing their mistakes. The friendship is real and so is the problem. The move is to fix the process without prosecuting the friend.","task":"Write the 2-3 sentences you'd say to them: direct on the facts, light on the verdict, clear on what changes.","tips":["Facts without theatrics: 'your rejects are ending up in my bin.'","Skip the motive trial — you don't need to know why to fix what.","The ask is the point: own bins, own counts, starting today."],"focus":["clarity","audience"]}
  ],
  "putting-it-together": [
    {"id":"together-mfg-early-01","level":"early","profession":"industrial","title":"The complete shift handoff","scenario":"End of shift, five minutes to write the handoff: the oven's zone 2 is running hot with a manual workaround, the labeler jammed twice, order 7734 is 60% done, and a QC hold sits in lane 3. Night shift reads this cold. Everything you've practiced applies at once.","task":"Write the full handoff note — live risks first, grouped and scannable, under 120 words.","tips":["Lead with what will bite them: the oven workaround, the hold.","Group by topic, one line each — no chronology.","Write for someone who wasn't here and can't call you."],"focus":["structure","clarity"],"placeholder":"WATCH FIRST: Oven zone 2 reads 10 high — I've been setting it to 330 to compensate; if it drifts more, call maintenance. Lane 3 pallet is on QC HOLD — do not move."},
    {"id":"together-mfg-early-02","level":"early","profession":"industrial","title":"The forwardable escalation","scenario":"The material staging area has shorted your line four times this month, each time costing 30-plus minutes. You're writing the escalation your supervisor could forward straight to the production manager: pattern, cost, recommendation, and the obvious objection already answered.","task":"Write the complete escalation in 4-5 sentences: pattern, counted cost, your recommendation, objection pre-empted.","tips":["Lead with the pattern and its total cost — that's the headline upstairs.","Own one clear recommendation, not a menu.","Pre-empt the likely objection (staffing) and keep every sentence forwardable."],"focus":["structure","impact"],"placeholder":"Line 3 has been shorted on staged material four times this month, costing just over two hours of production. I recommend staging be confirmed against the schedule at shift start —"},
    {"id":"together-mfg-early-03","level":"early","profession":"industrial","title":"One story, three channels","scenario":"A contaminated resin lot means the morning's product is on hold and the line restarted late. Three audiences need it: your supervisor (radio, now), QC (written, for the record), and your crew at the huddle (spoken, what changes for them). Same facts, three registers.","task":"Write all three versions: the 2-sentence radio call, the 3-sentence QC note, and the 2-sentence huddle words.","tips":["Supervisor: impact and what you need, fastest.","QC: lot numbers, time windows, quantities — the record.","Crew: what changes for their hands this shift."],"focus":["audience","structure"],"placeholder":"Radio: 'Morning product on line 2 is on hold — contaminated resin lot. Running clean since 10:30; I need a decision on the held pallets by 2:00.'"},
    {"id":"together-mfg-early-04","level":"early","profession":"industrial","title":"The complete near-miss report","scenario":"A raised dock plate edge caught your boot this morning — you stumbled next to moving pallet traffic and caught the rail. The full report form is in front of you: what happened, conditions, and prevention. This is every skill in one document: facts led, audience served, stakes concrete.","task":"Write the complete 4-5 sentence report: event, exact location, conditions that made it possible, prevention proposal.","tips":["Event and location first, in one factual sentence.","Conditions are the prevention gold: lighting, the plate's state, traffic.","End with a specific proposal, not 'be more careful.'"],"focus":["precision","structure"],"placeholder":"At 7:40 the raised edge of dock plate 2 caught my boot and I stumbled into the pallet-truck lane, catching the rail. The plate has sat 2 cm proud since last week's repair, and the dock lights were still off."},
    {"id":"together-mfg-early-05","level":"early","profession":"industrial","title":"Two minutes at the front of the room","scenario":"Your supervisor asked you to lead tomorrow's toolbox talk on the forklift blind corner — your near-miss, your corner, your two minutes. You need an opening that lands, one concrete change to ask for, and a close that sticks. Signposting, stakes, and the ask, all spoken.","task":"Write the full talk: 5-6 sentences, opening with the moment, asking for one specific behavior change.","tips":["Open inside the moment — forks, a meter, grinder noise.","One change only: stop-and-look at the marked line.","Close by making it mutual: drivers and walkers both own the corner."],"focus":["impact","audience"]},
    {"id":"together-mfg-early-06","level":"early","profession":"industrial","title":"The one-page improvement proposal","scenario":"The improvement program wants a written proposal for your line-side spare-parts kit idea. This is the full stack in one page: the 40-minute wait story, the counted cost, the scoped fix, the payback, and the inventory-control objection answered before it's raised.","task":"Write the 5-6 sentence proposal: problem story, cost, the scoped fix, payback, objection handled.","tips":["Open with the incident, one vivid sentence.","Scope the fix tightly — five named parts, signed out, counted monthly.","Payback in the same units as the cost: minutes of downtime."],"focus":["structure","impact"],"placeholder":"Last month line 4 stood dead 40 minutes waiting on a five-dollar drive belt from the central crib. Downtime waiting on common parts cost us just over three hours last quarter."},
    {"id":"together-mfg-early-07","level":"early","profession":"industrial","title":"The audit walkthrough, start to finish","scenario":"The auditor will spend ten minutes at your station tomorrow and your supervisor asked you to be ready. You'll need to describe your checks in order, answer what you don't know cleanly, and never guess. You're drafting your core walkthrough tonight — signposted, precise, calm.","task":"Write the 4-5 sentence walkthrough of your station's quality checks you'd deliver, structured so an outsider can follow.","tips":["Signpost the count up front: 'three checks, every hour.'","For each: what, how, where it's recorded.","Rehearse the escape hatch too: 'that's on the log — let me show you.'"],"focus":["structure","precision"],"placeholder":"Every hour I run three checks: fill weight, cap torque, and label placement. Fill weight is a three-bottle pull on the check-weigher, logged on this sheet with time and initials."},
    {"id":"together-mfg-early-08","level":"early","profession":"industrial","title":"The end-of-shift report with a decision in it","scenario":"Your end-of-shift report tonight has to do three jobs: give the numbers, explain the one exception, and get a decision from your supervisor about tomorrow's die change before the window closes. Numbers, narrative, and an ask — one tight message.","task":"Write the complete 4-sentence report: headline numbers, the exception in one line, the decision needed with its deadline.","tips":["Verdict first: made rate or didn't, by how much.","One exception, one sentence, resolved or flagged.","The ask carries a deadline: 'need your call by 7 a.m.'"],"focus":["structure","concision"],"placeholder":"4,350 of 4,400 — 99% of target. The gap was one 25-minute labeler jam, cleared, cause tagged for maintenance. Decision needed by 7 a.m.: the trim die change is slotted for tomorrow's 1:00 changeover —"},
    {"id":"together-mfg-early-09","level":"early","profession":"industrial","title":"The week's downtime, made legible","scenario":"Your supervisor asked you to summarize the week's downtime entries for the ops meeting. The raw log is fourteen scattered entries. The summary's job is to make the pattern visible — one machine is 60% of it — and end with what you'd do about it.","task":"Write the 3-4 sentence summary: total, the pattern that dominates, the recommendation.","tips":["Total first, then the split that matters: one machine, 60%.","Group the fourteen entries into three buckets, not a list.","The recommendation follows from the pattern — make the link explicit."],"focus":["structure","impact"],"placeholder":"We lost 6.2 hours to downtime this week, and the labeler alone was 3.7 of it — the same feed-clutch fault five times. The rest splits between material waits (1.5) and one-off jams."},
    {"id":"together-mfg-early-10","level":"early","profession":"industrial","title":"The 120-word draft, cut to 40","scenario":"You've drafted a message to your supervisor about the film supplier issue — 120 words of throat-clearing, backstory, and three separate apologies. Every fact in it matters to you; three facts matter to them. The final skill is cutting your own work without losing the load-bearing parts.","task":"Identify the three load-bearing facts a supervisor needs and rewrite the message in under 40 words.","tips":["The test for each sentence: does the reader act differently without it?","Keep the numbers, the deadline, the ask — cut the journey.","Apologies aren't facts; cut all three."],"focus":["concision","clarity"],"placeholder":"The new film lot is running 8% more jams than the last. I've kept us at rate by slowing the wrapper, but we should reject the lot — need your OK to call the supplier today."},
    {"id":"together-mfg-early-11","level":"early","profession":"industrial","title":"The stoppage call and its paper trail","scenario":"The press just faulted with a burning smell — you hit the stop, and now the same event needs two tellings: the 10-second radio call that gets maintenance moving, and the logbook entry that someone reads in three weeks. Urgent and permanent are different registers.","task":"Write both: the 1-2 sentence radio call, then the 2-3 sentence log entry with times and specifics.","tips":["Radio: machine, symptom, what you need — nothing else.","Log: times, the sequence, what was smelled and where, actions taken.","The log reader has no context; the radio listener needs no context."],"focus":["audience","precision"],"placeholder":"Radio: 'Press 4 is stopped — burning smell from the drive end. Need maintenance now, possible electrical.' Log: '13:22 — E-stopped press 4 after burning smell from drive-end housing during normal cycle...'"},
    {"id":"together-mfg-early-12","level":"early","profession":"industrial","title":"The defect report that stands alone","scenario":"A bin of 240 parts with undersized holes needs a report that works for three readers at once: QC deciding disposition, the setup crew hunting the cause, and whoever finds this bin in three weeks. One document, complete, no reader left guessing.","task":"Write the complete 4-5 sentence report: defect, scope with lot and count, when it started, probable cause flagged as probable, current containment.","tips":["Defect and scope first — measurable, not 'bad holes.'","Separate what you know from what you suspect, labeled.","Containment status closes it: where the bin is, what's tagged."],"focus":["precision","structure"],"placeholder":"Hole diameter under spec on all four positions — approx. 240 pcs from lot 3319, first bad part traced to the 10:15 tool change. Probable cause (unconfirmed): the replacement drill bit —"},
    {"id":"together-mfg-early-13","level":"early","profession":"industrial","title":"The station in thirty minutes","scenario":"A temp with general floor experience covers your station during your medical appointment tomorrow — thirty minutes, unsupervised. Your cover note is the whole interface: safe operation, the two quirks that will actually come up, and the bright line for when to stop and call.","task":"Write the complete cover note in 5-6 sentences a stranger can run the station from.","tips":["Order it by what happens, not by what's interesting.","Name buttons and locations like they've never seen them.","End with the stop-and-call line — the note's most important sentence."],"focus":["audience","clarity"],"placeholder":"Keep the feed hopper above half — it's the gauge on the left, refill bags are on the rack behind you. If the jam light comes on, press the yellow STOP, clear the part with the hook (never hands), then green to restart."},
    {"id":"together-mfg-early-14","level":"early","profession":"industrial","title":"Thirty seconds, three items","scenario":"At tomorrow's huddle you have thirty seconds and three items: the line met rate, the new film lot starts today and needs watching, and you need a volunteer for the 5S trial. Signposted, ordered, and short enough that the third item still gets heard.","task":"Write the full 30-second huddle update, signposted, with the ask landing last and clearly.","tips":["Count them off: 'three things.'","Good news gets one sentence; the watch-item gets the specifics.","End on the ask — last position is the one people remember."],"focus":["structure","concision"],"placeholder":"Three things. One: we hit rate yesterday, clean shift. Two: the new film lot starts today — first hour, watch the wrapper tension and flag me on anything odd. Three: I need one volunteer for the 5S trial —"},
    {"id":"together-mfg-early-15","level":"early","profession":"industrial","title":"Bad news with a plan attached","scenario":"The main drive motor is failing — vibration up, temperature up, maybe two weeks left. The full message to your supervisor is bad news plus recommendation plus the objection they'll raise (the order backlog) already handled. One message, every skill, real stakes.","task":"Write the 4-5 sentence message: the finding, the evidence trend, your recommended planned stop, and the backlog objection pre-empted.","tips":["Finding first, trend as evidence — numbers across shifts.","Recommend the specific window, not 'soon.'","Answer the backlog objection with the unplanned-failure math."],"focus":["impact","structure"],"placeholder":"The line 2 main drive is failing — vibration has doubled in two weeks and it's running 15 degrees hotter. I recommend a planned replacement this Sunday. I know the backlog argues against downtime —"},
    {"id":"together-mfg-early-16","level":"early","profession":"industrial","title":"The work order that jumps the queue","scenario":"Maintenance triages forty open orders by whatever the first line tells them. Yours has everything riding on it: the bearing that will take the whole line down. Symptom, pattern, production risk, and a specific ask — the complete persuasion stack in a work-order box.","task":"Write the complete work-order text in 3-4 sentences: symptom with trend, what failure costs, the specific slot you're asking for.","tips":["First line is the triage line: machine, symptom, trajectory.","Production risk in their terms: full line, three-day part lead time.","Ask for the slot by name: 'this week's PM window.'"],"focus":["precision","impact"],"placeholder":"Line 4 main conveyor drive bearing: grinding, audibly worse each shift for three shifts. Failure stops the entire line, and the bearing is a three-day lead-time part."},
    {"id":"together-mfg-early-17","level":"early","profession":"industrial","title":"Five minutes to shift end","scenario":"It's 5:55, your ride leaves at 6:05, and you've just spotted rust-colored specks in the hopper feed — possible contamination that night shift will run straight through. No time for a perfect message. Risk, action taken, ask — in the time you have.","task":"Write the message you'd fire off in ninety seconds: the risk, what you did, what night shift must do.","tips":["Headline first — 'possible contamination, line 2 hopper.'","One action you took: held the last pallet, flagged the bin.","One instruction for nights: don't run until QC clears it."],"focus":["clarity","impact"],"placeholder":"Possible contamination line 2 — rust-colored specks in the hopper feed, spotted 5:50. I've held the last pallet and tagged the hopper DO NOT RUN. Nights: do not restart until QC checks the feed —"},
    {"id":"together-mfg-early-18","level":"early","profession":"industrial","title":"Briefing the visiting engineer","scenario":"The corporate engineer arrives tomorrow to investigate your line's reject spike, and your supervisor wants you to give the opening brief. Your job: the observed timeline, what changed and when, your hunch clearly labeled as a hunch — the floor's knowledge, organized for a technical stranger.","task":"Write the 4-5 sentence brief: the spike in numbers, the timeline, the two things that changed, your labeled hunch.","tips":["Numbers and dates first — the shape of the problem.","List what changed near the onset: material lot, speed increase.","Your hunch goes last, flagged: 'my read from the floor, unverified.'"],"focus":["audience","structure"],"placeholder":"Rejects went from 2% to 7% starting the night of the 14th, all short-shots on the two back cavities. Two things changed that week: the new resin lot on the 13th, and line speed up 10% on the 12th."},
    {"id":"together-mfg-early-19","level":"early","profession":"industrial","title":"The new hire's first solo hour","scenario":"The new hire runs your station solo for the first time tomorrow while you're at the dentist — one hour. Your note is their trainer, safety net, and permission slip in one: what to run, what to watch, what success looks like, and exactly when to stop and call the line lead.","task":"Write the complete 5-6 sentence note for their first unsupervised hour.","tips":["Scope the hour: just keep the current order running — no changeovers.","Give the one likely event and its exact response.","Define 'stop and call' precisely — and say calling is the RIGHT move, not failure."],"focus":["audience","clarity"],"placeholder":"Your only job this hour: keep order 7734 running at the set speed — no changes, no changeovers. The one thing likely to happen is a label jam: yellow STOP, clear it with the hook, green to restart."},
    {"id":"together-mfg-early-20","level":"early","profession":"industrial","title":"The hold, communicated everywhere it counts","scenario":"You've put a pallet on quality hold. A hold only works if every channel says the same thing: the tag a stranger reads in the aisle, the message QC needs to disposition it, and the line note so your own crew doesn't ship it at 3 a.m. Three artifacts, one hold.","task":"Write all three: the 2-line tag, the 2-sentence QC message with specifics, and the 1-line note for the crew board.","tips":["Tag: what, why in five words, who releases it.","QC: lot, window, defect, count — everything disposition needs.","Crew note: one unmissable line with the pallet's location."],"focus":["audience","precision"],"placeholder":"TAG: HOLD — failed seal check, awaiting QC. Release by QC only (ext. 4412). / QC: Pallet 7 of order 5561 on hold — 3 of 10 seal checks failed, 13:00-14:00 window, lot 5512..."},
    {"id":"together-mfg-early-21","level":"early","profession":"industrial","title":"The shortage email worth forwarding","scenario":"Carton shortages have idled your line three times in two weeks — a supplier issue, above your pay grade to fix, but not above your pay grade to document. The email to your supervisor should be clean enough to forward to purchasing unedited: pattern, cost, and the specific data attached.","task":"Write the complete 4-5 sentence email: the pattern with dates, the counted cost, what you need, written for the forwarded audience too.","tips":["Dates and durations make it purchasing-proof: three incidents, listed.","Cost in units and hours — the language that crosses departments.","Keep your tone neutral; the email may travel farther than you send it."],"focus":["audience","impact"],"placeholder":"Line 3 has been idled by carton shortages three times in two weeks: June 19 (45 min), June 24 (30 min), July 1 (70 min) — about 1,200 units of lost production total."},
    {"id":"together-mfg-early-22","level":"early","profession":"industrial","title":"The note that survives the weekend","scenario":"You're the last regular operator out before the long weekend; a skeleton crew runs Saturday, a different one Monday, and you're back Tuesday. One note has to carry three shifts: the live workaround, the parts arriving Monday, and the check due Sunday. Nothing verbal survives — only the note.","task":"Write the weekend note in 5-6 sentences, organized by day, readable by three different crews.","tips":["Structure by when, not by topic: Saturday / Sunday / Monday.","Every instruction self-contained — no 'as discussed.'","Put the one all-weekend rule at the top, above the days."],"focus":["structure","clarity"],"placeholder":"ALL WEEKEND: oven zone 2 reads 10 degrees high — set 330 to get a true 340; if the gap grows past 15, stop and call maintenance. SATURDAY: order 7738 runs at 55/min —"},
    {"id":"together-mfg-early-23","level":"early","profession":"industrial","title":"Your statement for the record","scenario":"There was a lockout incident on your line yesterday — no injury, big investigation. You're asked for a written statement of what you saw. This document outlives everyone's memory: facts in sequence, times where you know them, edges marked where you don't, zero speculation.","task":"Write the 4-5 sentence statement: what you observed in order, with times, your position, and the boundaries of what you could see.","tips":["Sequence with times: 'at about 14:20 I saw...'","State your vantage point — it defines what your words can carry.","Mark every edge: 'I did not see who removed the lock.'"],"focus":["precision","structure"],"placeholder":"At about 14:20 I was at the line 3 control panel, roughly ten meters from the palletizer, when I heard it cycle. I saw the maintenance lock was no longer on the disconnect. I did not see who removed it —"},
    {"id":"together-mfg-early-24","level":"early","profession":"industrial","title":"The memo that goes upstairs","scenario":"Your supervisor was impressed by your photo-eye pattern analysis and asked you to write it up as a short memo they'll put in front of the plant manager. Highest-stakes audience you've written for: the pattern, the cost, the root-cause recommendation — executive-brief tight, floor-level true.","task":"Write the 4-5 sentence memo: finding, cost, recommendation, and the cheap first step — no floor shorthand.","tips":["First sentence carries the whole memo: pattern plus annual cost.","Translate everything — the plant manager doesn't know 'the eye.'","End with the smallest fundable step: a two-hour root-cause inspection."],"focus":["audience","impact"],"placeholder":"One sensor on line 3 has caused four production stoppages in four weeks — 190 minutes of downtime, roughly 2,400 units. Replacing it each time has not held; the failures suggest an upstream cause."},
    {"id":"together-mfg-early-25","level":"early","profession":"industrial","title":"Everything at once","scenario":"The capstone, from real life: the recurring changeover chaos costs the plant an hour a day, you have the data, a scoped fix, and one shot — a message your supervisor will read between meetings and, if it's good, act on today. BLUF, structure, stakes, the objection handled, and an ask with a date. All of it.","task":"Write the complete message in 5-6 sentences, deploying every skill in the course, ending with a yes-able ask.","tips":["First sentence: the cost and the fix, together.","Middle: the evidence in two tight sentences, the objection killed in one.","Last sentence: the specific, dated, easy-to-grant ask."],"focus":["structure","impact"],"placeholder":"We lose about an hour a day to changeover scrambles, and a two-part fix — pre-staged materials and a one-page checklist — recovers most of it. I've timed three weeks of changeovers:"}
  ]
};
